"use client";

import React, { useState, useEffect } from 'react';
import Link from 'next/link';
import { Goals } from '@/components/widgets/Goals';
import { GoalsSummary, type TimeFilter } from '@/components/widgets/GoalsSummary';
import { GoalsInsights } from '@/components/widgets/GoalsInsights';
import { PageTitle, SectionTitle, Description } from '@/components/ui/Text';

export default function GoalsPage() {
  const [mounted, setMounted] = useState(false);
  const [filter, setFilter] = useState<TimeFilter>('Custom Month');
  const [selectedMonth, setSelectedMonth] = useState(new Date().getMonth());
  const [selectedYear, setSelectedYear] = useState(new Date().getFullYear());
  const [view, setView] = useState<'grid' | 'gantt'>('grid');
  const [showInsights, setShowInsights] = useState(false);

  useEffect(() => {
    setMounted(true);
  }, []);

  if (!mounted) return null;

  return (
    <main className="min-h-screen bg-zinc-50 dark:bg-zinc-950 text-zinc-900 dark:text-zinc-100 selection:bg-teal-500/30 font-sans p-4 md:p-8 xl:p-12 transition-colors duration-200">
      <div className="mx-auto w-full max-w-7xl">
        <header className="mb-10 flex flex-col md:flex-row md:items-end justify-between gap-4">
          <div className="flex flex-col items-start">
            <PageTitle>
              Goals
            </PageTitle>
            <Description>Prioritize what matters most.</Description>
          </div>
          
          <button
            onClick={() => setShowInsights(!showInsights)}
            className={`flex items-center gap-2 px-6 py-2.5 rounded-2xl text-sm font-bold transition-all shadow-sm border ${
              showInsights 
                ? 'bg-teal-600 border-teal-500 text-white shadow-teal-500/20 active:scale-95' 
                : 'bg-white dark:bg-zinc-900 border-zinc-200 dark:border-zinc-800 text-zinc-600 dark:text-zinc-400 hover:border-teal-500/50 hover:text-teal-600'
            }`}
          >
            <svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round"><path d="M21.21 15.89A10 10 0 1 1 8 2.83" /><path d="M22 12A10 10 0 0 0 12 2v10z" /></svg>
            {showInsights ? 'Hide Insights' : 'Show Insights'}
          </button>
        </header>
        
        {/* Overview Section */}
        <section className="w-full relative fade-in mb-14">
          <div className="flex flex-col md:flex-row justify-between items-start md:items-end gap-4 mb-8">
            <SectionTitle className="mb-0">Overview</SectionTitle>
            
            <div className="flex flex-wrap gap-2 items-center w-full md:w-auto">
              {filter === 'Custom Month' && (
                <div className="flex gap-2 flex-1 sm:flex-none">
                  <select
                    value={selectedMonth}
                    onChange={(e) => setSelectedMonth(parseInt(e.target.value))}
                    className="flex-1 sm:flex-none appearance-none bg-zinc-50 hover:bg-zinc-100 dark:bg-zinc-950 dark:hover:bg-zinc-800 transition-colors text-xs font-semibold text-zinc-700 dark:text-zinc-300 rounded-xl px-3 py-2 cursor-pointer outline-none border border-zinc-200 dark:border-zinc-700 focus:ring-2 focus:ring-teal-500/50 shadow-sm"
                  >
                    {Array.from({ length: 12 }, (_, i) => (
                      <option key={i} value={i}>
                        {new Date(2000, i, 1).toLocaleDateString('en-US', { month: 'short' })}
                      </option>
                    ))}
                  </select>
                  <select
                    value={selectedYear}
                    onChange={(e) => setSelectedYear(parseInt(e.target.value))}
                    className="flex-1 sm:flex-none appearance-none bg-zinc-50 hover:bg-zinc-100 dark:bg-zinc-950 dark:hover:bg-zinc-800 transition-colors text-xs font-semibold text-zinc-700 dark:text-zinc-300 rounded-xl px-3 py-2 cursor-pointer outline-none border border-zinc-200 dark:border-zinc-700 focus:ring-2 focus:ring-teal-500/50 shadow-sm"
                  >
                    {Array.from({ length: 5 }, (_, i) => 2026 + i).map(y => (
                      <option key={y} value={y}>{y}</option>
                    ))}
                  </select>
                </div>
              )}
              <select
                value={filter}
                onChange={(e) => setFilter(e.target.value as TimeFilter)}
                className="flex-1 sm:flex-none appearance-none bg-zinc-50 hover:bg-zinc-100 dark:bg-zinc-950 dark:hover:bg-zinc-800 transition-colors text-xs font-semibold text-zinc-700 dark:text-zinc-300 rounded-xl px-3 py-2 cursor-pointer outline-none border border-zinc-200 dark:border-zinc-700 focus:ring-2 focus:ring-teal-500/50 shadow-sm"
              >
                <option value="1 Day">1 Day</option>
                <option value="7 Days">7 Days</option>
                <option value="1 Month">1 Month</option>
                <option value="6 Months">6 Months</option>
                <option value="1 Year">1 Year</option>
                <option value="Custom Month">Current Month</option>
              </select>
              <Link href="/goals" className="px-4 py-2 text-sm font-semibold rounded-xl bg-teal-50 text-teal-700 hover:bg-teal-100 dark:bg-teal-500/10 dark:text-teal-400 dark:hover:bg-teal-500/20 transition-colors border border-teal-200 dark:border-teal-900/50 whitespace-nowrap">View All</Link>
            </div>
          </div>
          
          <GoalsSummary 
            filter={filter} 
            selectedMonth={selectedMonth} 
            selectedYear={selectedYear} 
          />
        </section>

        {/* Insights Section */}
        {showInsights && (
          <section className="w-full relative fade-in mb-14 animate-in slide-in-from-top-4 duration-500">
            <div className="flex items-center gap-3 mb-8">
              <SectionTitle className="mb-0 text-teal-600 dark:text-teal-400">Deep Insights</SectionTitle>
              <div className="h-[1px] flex-1 bg-gradient-to-r from-teal-500/20 to-transparent"></div>
            </div>
            <GoalsInsights 
              filter={filter} 
              selectedMonth={selectedMonth} 
              selectedYear={selectedYear} 
            />
          </section>
        )}

        {/* Goals Tracker Section */}
        <section className="w-full relative fade-in">
          <div className="flex flex-row justify-between items-center gap-4 mb-8">
            <SectionTitle className="mb-0">Goals Tracker</SectionTitle>

            
            <div className="bg-zinc-100 dark:bg-zinc-800/50 p-1 rounded-xl flex items-center gap-1 shadow-inner">
              <button
                onClick={() => setView('grid')}
                className={`px-4 py-1.5 rounded-lg text-xs font-semibold transition-all flex items-center gap-2 ${view === 'grid' ? 'bg-white dark:bg-zinc-900 text-zinc-900 dark:text-white shadow-sm' : 'text-zinc-500 hover:text-zinc-900 dark:hover:text-white' }`}
              >
                <svg xmlns="http://www.w3.org/2000/svg" width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round"><rect x="3" y="3" width="7" height="7" /><rect x="14" y="3" width="7" height="7" /><rect x="14" y="14" width="7" height="7" /><rect x="3" y="14" width="7" height="7" /></svg>
                Grid
              </button>
              <button
                onClick={() => setView('gantt')}
                className={`px-4 py-1.5 rounded-lg text-xs font-semibold transition-all flex items-center gap-2 ${view === 'gantt' ? 'bg-white dark:bg-zinc-900 text-zinc-900 dark:text-white shadow-sm' : 'text-zinc-500 hover:text-zinc-900 dark:hover:text-white' }`}
              >
                <svg xmlns="http://www.w3.org/2000/svg" width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round"><path d="M3 10h18M3 14h18M3 18h18M7 6v4M17 6v4" /></svg>
                Gantt
              </button>
            </div>
          </div>
          
          <Goals view={view} setView={setView} />
        </section>
      </div>
    </main>
  );
}

"use client";
import React, { useState, useEffect } from 'react';
import Link from 'next/link';
import { Habits } from '@/components/widgets/Habits';
import { HabitsOverview, type TimeFilter } from '@/components/widgets/HabitsOverview';
import { PageTitle, SectionTitle, Text, Description } from '@/components/ui/Text';
import { HabitDetailPanel } from '@/components/widgets/HabitDetailPanel';
import { TrendingUp, TrendingDown, Star, Target, Zap } from 'lucide-react';
import { getPrefixedKey } from '@/lib/keys';

export default function HabitsPage() {
  const [mounted, setMounted] = useState(false);
  const [filter, setFilter] = useState<TimeFilter>('Custom Month');
  const [selectedMonth, setSelectedMonth] = useState(new Date().getMonth());
  const [selectedYear, setSelectedYear] = useState(new Date().getFullYear());
  const [selectedHabit, setSelectedHabit] = useState<any>(null);

  // Stats for summary bar
  const [summaryStats, setSummaryStats] = useState<{
    successRate: number;
    trend: number | null;
    perfectDays: number | null;
    totalLogged: number;
  }>({ successRate: 0, trend: null, perfectDays: null, totalLogged: 0 });

  useEffect(() => {
    setMounted(true);
  }, []);

  // Update summary stats based on current filter/Selection
  useEffect(() => {
    if (!mounted) return;

    const loadSummary = () => {
      const saved = localStorage.getItem(getPrefixedKey('os_habits'));
      if (!saved) return;
      try {
        const habits = JSON.parse(saved);
        if (!Array.isArray(habits)) return;

        const now = new Date();
        const today = new Date(now.getFullYear(), now.getMonth(), now.getDate());

        let done = 0, missed = 0;
        let pDays = 0;

        if (filter === 'Custom Month') {
          const mKey = `${selectedYear}-${selectedMonth}`;
          const daysInMonth = new Date(selectedYear, selectedMonth + 1, 0).getDate();
          const activeHabits = habits.filter(h => !h.monthScope || h.monthScope.includes(mKey));

          for (let d = 1; d <= daysInMonth; d++) {
            const dateOfRecord = new Date(selectedYear, selectedMonth, d);
            if (dateOfRecord > today) continue;

            let dDone = 0, dMissed = 0;
            activeHabits.forEach(h => {
              const s = h.records?.[mKey]?.[d - 1];
              if (s === 'done') { done++; dDone++; }
              else if (s === 'missed') { missed++; dMissed++; }
            });

            if (activeHabits.length > 0 && dDone === activeHabits.length) pDays++;
          }

          // Trend calculation
          const lastMonthDate = new Date(selectedYear, selectedMonth - 1, 1);
          const lastMKey = `${lastMonthDate.getFullYear()}-${lastMonthDate.getMonth()}`;
          const lastDaysInMonth = new Date(lastMonthDate.getFullYear(), lastMonthDate.getMonth() + 1, 0).getDate();
          let lDone = 0, lMissed = 0;
          habits.forEach(h => {
            const isActiveInLast = !h.monthScope || h.monthScope.includes(lastMKey);
            if (!isActiveInLast) return;
            for (let d = 0; d < lastDaysInMonth; d++) {
              const s = h.records?.[lastMKey]?.[d];
              if (s === 'done') lDone++;
              else if (s === 'missed') lMissed++;
            }
          });
          const lTotal = lDone + lMissed;
          const lRate = lTotal > 0 ? (lDone / lTotal) * 100 : null;
          const curTotal = done + missed;
          const curRate = curTotal > 0 ? (done / curTotal) * 100 : 0;

          setSummaryStats({
            successRate: Math.round(curRate),
            trend: lRate !== null ? Math.round(curRate - lRate) : null,
            perfectDays: pDays,
            totalLogged: curTotal
          });
        } else {
          // Adapt to other filters
          let daysToLookBack = 30;
          if (filter === '1 Day') daysToLookBack = 1;
          else if (filter === '7 Days') daysToLookBack = 7;
          else if (filter === '1 Month') daysToLookBack = 30;
          else if (filter === '6 Months') daysToLookBack = 180;
          else if (filter === '1 Year') daysToLookBack = 365;

          const activeHabitsSet = new Set<string>();
          for (let i = 0; i < daysToLookBack; i++) {
            const checkDate = new Date(today);
            checkDate.setDate(today.getDate() - i);
            const mKey = `${checkDate.getFullYear()}-${checkDate.getMonth()}`;
            const dIdx = checkDate.getDate() - 1;

            habits.forEach(h => {
              const isActive = !h.monthScope || h.monthScope.includes(mKey);
              if (isActive) {
                activeHabitsSet.add(h.id);
                const s = h.records?.[mKey]?.[dIdx];
                if (s === 'done') done++;
                else if (s === 'missed') missed++;
              }
            });
          }

          const curTotal = done + missed;
          setSummaryStats({
            successRate: curTotal > 0 ? Math.round((done / curTotal) * 100) : 0,
            trend: null,
            perfectDays: null,
            totalLogged: curTotal
          });
        }
      } catch (e) { console.error("Error parsing block:", e); }
    };

    loadSummary();
    const inv = setInterval(loadSummary, 5000); // Poll for changes
    window.addEventListener('local-storage-change', loadSummary);
    return () => {
      clearInterval(inv);
      window.removeEventListener('local-storage-change', loadSummary);
    };
  }, [mounted, filter, selectedMonth, selectedYear]);

  if (!mounted) return null;

  return (
    <main className="min-h-screen bg-zinc-50 dark:bg-zinc-950 text-zinc-900 dark:text-zinc-100 selection:bg-teal-500/30 font-sans p-4 md:p-8 xl:p-12 transition-colors duration-200">
