'use client';

import { useEffect, useState } from 'react';
import { supabase } from '@/lib/supabase';
import { LoginPage } from './LoginPage';

export function AuthGuard({ children }: { children: React.ReactNode }) {
 const [session, setSession] = useState<any>(null);
 const [loading, setLoading] = useState(true);
 const [authorized, setAuthorized] = useState(false);
 const [isMounted, setIsMounted] = useState(false);
 const [isLocal, setIsLocal] = useState(false);

 useEffect(() => {
 setIsMounted(true);
 setIsLocal(window.location.hostname === 'localhost' || window.location.hostname === '127.0.0.1');

 // Get initial session
 supabase.auth.getSession().then(({ data: { session } }) => {
 setSession(session);
 checkAuthorization(session);
 setLoading(false);
 });

 // Listen for auth changes
 const {
 data: { subscription },
 } = supabase.auth.onAuthStateChange((_event, session) => {
 setSession(session);
 checkAuthorization(session);
 });

 return () => subscription.unsubscribe();
 }, []);

 const checkAuthorization = (currentSession: any) => {
 const authorizedEmail = process.env.NEXT_PUBLIC_AUTH_EMAIL;
 if (!currentSession) {
 setAuthorized(false);
 return;
 }

 if (authorizedEmail && currentSession.user?.email?.toLowerCase() !== authorizedEmail.toLowerCase()) {
 // Logged in but not the authorized user - sign them out
 supabase.auth.signOut();
 setAuthorized(false);
 return;
 }

 setAuthorized(true);
 };

 if (!isMounted) {
 return (
 <div className="fixed inset-0 flex items-center justify-center bg-[#0a0a0a] z-[9999]">
 <div className="w-8 h-8 border-2 border-white/20 border-t-white rounded-full animate-spin" />
 </div>
 );
 }

 if (loading && !isLocal) {
 return (
 <div className="fixed inset-0 flex items-center justify-center bg-[#0a0a0a] z-[9999]">
 <div className="w-8 h-8 border-2 border-white/20 border-t-white rounded-full animate-spin" />
 </div>
 );
 }

 if (!isLocal && (!session || !authorized)) {
 return <LoginPage />;
 }

 return <>{children}</>;
}

"use client";
import React, { useState, useEffect } from 'react';
import Link from 'next/link';
import { usePathname } from 'next/navigation';
import { 
 LayoutDashboard, 
 Target, 
 Repeat, 
 CircleDollarSign, 
 ShoppingBasket,
 BookMarked,
 Rocket,
 ChevronUp,
 FileText,
 Shirt,
 Activity
} from 'lucide-react';

export function FloatingNavbar() {
 const pathname = usePathname();
 const [isVisible, setIsVisible] = useState(false);
 const [isModalOpen, setIsModalOpen] = useState(false);

 useEffect(() => {
 const handleScroll = () => {
 // Show navbar when scrolled down more than 100px
 if (window.scrollY > 100) {
 setIsVisible(true);
 } else {
 setIsVisible(false);
 }
 };

 const checkModals = () => {
 // Look for common modal patterns in the app
 const modal = document.querySelector('.fixed.inset-0.z-\\[100\\]') || 
 document.querySelector('.fixed.inset-0.z-\\[101\\]');
 setIsModalOpen(!!modal);
 };

 window.addEventListener('scroll', handleScroll, { passive: true });
 
 // Initial checks
 handleScroll();
 checkModals();

 // Use MutationObserver to detect modal additions/removals
 const observer = new MutationObserver(() => {
 checkModals();
 });

 observer.observe(document.body, { 
 childList: true, 
 subtree: true,
 attributeFilter: ['class'] 
 });

 return () => {
 window.removeEventListener('scroll', handleScroll);
 observer.disconnect();
 };
 }, []);

 const navItems = [
 { name: 'Dashboard', href: '/', icon: LayoutDashboard },
 { name: 'Goals', href: '/goals', icon: Target },
 { name: 'Habits', href: '/habits', icon: Repeat },
 { name: 'Books', href: '/books', icon: BookMarked },
 { name: 'Finances', href: '/finances', icon: CircleDollarSign },
 { name: 'Content System', href: '/content-system', icon: Rocket },
 { name: 'Expenses', href: '/pantry', icon: ShoppingBasket },
 { name: 'Wardrobe', href: '/wardrobe', icon: Shirt },
 { name: 'Health', href: '/health-system', icon: Activity },
 ];


 const scrollToTop = () => {
 window.scrollTo({
 top: 0,
 behavior: 'smooth',
 });
 };

 return (
 <div 
 className={`fixed bottom-8 left-0 right-0 mx-auto z-[999] w-fit max-w-[95vw] transition-all duration-500 cubic-bezier(0.4, 0, 0.2, 1) ${ isVisible && !isModalOpen ? 'opacity-100 translate-y-0 scale-100' : 'opacity-0 translate-y-12 scale-90 pointer-events-none' }`}
 >
 <nav className="flex items-center gap-1 p-2 px-4 bg-white/70 dark:bg-zinc-900/80 backdrop-blur-2xl border border-zinc-200/50 dark:border-zinc-800/50 rounded-2xl shadow-[0_20px_50px_rgba(0,0,0,0.15)] dark:shadow-[0_20px_50px_rgba(0,0,0,0.3)] overflow-x-auto scrollbar-hide max-w-full">
 {navItems.map((item) => {
 // Handle trailing slashes and potential basePath differences
 const normalizedPathname = pathname?.replace(/\/$/, '') || '/';
 const normalizedHref = item.href.replace(/\/$/, '') || '/';
 const isActive = normalizedPathname === normalizedHref;
 
 const Icon = item.icon;
 
 return (
 <Link
 key={item.href}
 href={item.href}
 className={`relative flex items-center justify-center p-2 sm:p-2.5 lg:p-3 rounded-xl transition-all duration-300 group flex-shrink-0 ${ isActive ? 'bg-zinc-900 text-white dark:bg-white dark:text-zinc-900 shadow-xl shadow-zinc-900/20 dark:shadow-white/10' : 'text-zinc-500 hover:text-zinc-900 dark:text-zinc-400 dark:hover:text-white hover:bg-zinc-100 dark:hover:bg-zinc-800' }`}
 >
 <Icon size={22} className={`${isActive ? 'scale-110' : 'group-hover:scale-110'} transition-transform duration-300`} />

 {/* Ping effect for active item */}
 {isActive && (
 <span className="absolute -top-1 -right-1 w-2 h-2 bg-teal-500 rounded-full border-2 border-white dark:border-zinc-900 animate-pulse" />
 )}
 </Link>
 );
 })}

 {/* Scroll to Top Button */}
 <div className="hidden sm:block w-px h-6 bg-zinc-200/50 dark:bg-zinc-800/50 mx-0.5" />
 <button
 onClick={scrollToTop}
 className="hidden sm:flex items-center justify-center p-2.5 rounded-xl text-zinc-500 hover:text-zinc-900 dark:text-zinc-400 dark:hover:text-white hover:bg-zinc-100 dark:hover:bg-zinc-800 transition-all duration-300 group flex-shrink-0"
 aria-label="Scroll to top"
 >
 <ChevronUp size={22} className="group-hover:-translate-y-1 transition-transform duration-300" />
 </button>
 </nav>
 </div>
 );
}

'use client';

import { useState, useEffect } from 'react';
import { supabase } from '@/lib/supabase';
import { PageTitle } from './ui/Text';

export function LoginPage() {
 const [email, setEmail] = useState('');
 const [loading, setLoading] = useState(false);
 const [message, setMessage] = useState<{ type: 'success' | 'error', text: string } | null>(null);
 const [isMounted, setIsMounted] = useState(false);

 useEffect(() => {
 setIsMounted(true);
 }, []);

 const handleLogin = async (e: React.FormEvent) => {
 e.preventDefault();
 setLoading(true);
 setMessage(null);

 const authorizedEmail = process.env.NEXT_PUBLIC_AUTH_EMAIL;
 
 // Strict client-side check for the authorized email
 if (authorizedEmail && email.toLowerCase() !== authorizedEmail.toLowerCase()) {
 setMessage({ type: 'error', text: 'Unauthorized email address. Access denied.' });
 setLoading(false);
 return;
 }

 try {
 const { error } = await supabase.auth.signInWithOtp({
 email,
 options: {
 emailRedirectTo: `${window.location.origin}/my-dashboard/`,
 },
 });

 if (error) throw error;
 setMessage({ type: 'success', text: 'Check your email for the magic link!' });
 } catch (error: any) {
 setMessage({ type: 'error', text: error.message || 'An error occurred during sign in.' });
 } finally {
 setLoading(false);
 }
 };

 if (!isMounted) return null;

 return (
 <div className="fixed inset-0 flex items-center justify-center bg-[#0a0a0a] z-[9999]">
 {/* Background Decorative Elements */}
 <div className="absolute top-0 left-0 w-full h-full overflow-hidden pointer-events-none">
 <div className="absolute top-[-10%] left-[-10%] w-[40%] h-[40%] bg-blue-500/10 rounded-full blur-[120px]" />
 <div className="absolute bottom-[-10%] right-[-10%] w-[40%] h-[40%] bg-purple-500/10 rounded-full blur-[120px]" />
 </div>

 <div className="relative w-full max-w-md p-8 mx-4 bg-[#111111] border border-white/10 rounded-2xl shadow-2xl backdrop-blur-xl">
 <div className="flex flex-col items-center mb-8">
 <div className="w-16 h-16 bg-gradient-to-tr from-blue-500 to-purple-600 rounded-2xl flex items-center justify-center mb-4 shadow-lg shadow-blue-500/20">
 <svg xmlns="http://www.w3.org/2000/svg" className="w-8 h-8 text-white" fill="none" viewBox="0 0 24 24" stroke="currentColor">
 <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 15v2m-6 4h12a2 2 0 002-2v-6a2 2 0 00-2-2H6a2 2 0 00-2 2v6a2 2 0 002 2zm10-10V7a4 4 0 00-8 0v4h8z" />
 </svg>
 </div>
 <PageTitle className="text-white">Access Locked</PageTitle>
 <p className="text-gray-400 mt-2 text-center text-sm">
 Enter your authorized email to receive a magic link.
 </p>
 </div>

 <form onSubmit={handleLogin} className="space-y-4">
 <div>
 <label htmlFor="email" className="block text-xs font-medium text-gray-400 uppercase mb-1.5 ml-1">
 Email Address
 </label>
 <input
 id="email"
 type="email"
 placeholder="name@example.com"
 value={email}
 onChange={(e) => setEmail(e.target.value)}
 required
 className="w-full px-4 py-3 bg-[#1a1a1a] border border-white/5 rounded-xl text-white placeholder-gray-600 focus:outline-none focus:ring-2 focus:ring-blue-500/40 focus:border-blue-500/40 transition-all duration-200"
 />
 </div>

 <button
 type="submit"
 disabled={loading}
 className="group relative w-full flex items-center justify-center px-4 py-3.5 bg-white text-black font-semibold rounded-xl hover:bg-gray-100 disabled:opacity-50 disabled:cursor-not-allowed transition-all duration-200 overflow-hidden"
 >
 {loading ? (
 <div className="w-5 h-5 border-2 border-black/20 border-t-black rounded-full animate-spin" />
 ) : (
 <span className="flex items-center">
 Send Magic Link
 <svg xmlns="http://www.w3.org/2000/svg" className="ml-2 w-4 h-4 transform group-hover:translate-x-1 transition-transform" fill="none" viewBox="0 0 24 24" stroke="currentColor">
 <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M14 5l7 7m0 0l-7 7m7-7H3" />
 </svg>
 </span>
 )}
 </button>
 </form>

 {message && (
 <div className={`mt-6 p-4 rounded-xl text-sm font-medium border ${ message.type === 'success' ? 'bg-emerald-500/10 border-emerald-500/20 text-emerald-400' : 'bg-rose-500/10 border-rose-500/20 text-rose-400' } animate-in fade-in slide-in-from-top-2 duration-300`}>
 {message.text}
 </div>
 )}

 <div className="mt-8 pt-6 border-t border-white/5 flex justify-center">
 <p className="text-xs text-gray-500 uppercase">
 &copy; {new Date().getFullYear()} Security System Active
 </p>
 </div>
 </div>
 </div>
 );
}

"use client";
import React, { useState } from 'react';
import Link from 'next/link';
import { usePathname } from 'next/navigation';
import { supabase } from '@/lib/supabase';
import { SyncStatus } from './SyncStatus';
import { useSyncStatus } from '@/context/SyncContext';
import { Menu, X } from 'lucide-react';

export function NavigationBar() {
 const pathname = usePathname();
 const { syncStatus, isDevelopment } = useSyncStatus();
 const [mobileMenuOpen, setMobileMenuOpen] = useState(false);

 const navLinks = [
 { name: 'Dashboard', path: '/' },
