 { name: 'Books', path: '/books' },
 { name: 'Finances', path: '/finances' },
 { name: 'Content System', path: '/content-system' },
 { name: 'Expenses', path: '/pantry' },
 { name: 'Wardrobe', path: '/wardrobe' },
 { name: 'Health', path: '/health-system' },
