'use client';

import { useEffect, useState, useRef } from "react";
import { MsalProvider } from "@azure/msal-react";
import { getMsalInstance, loginRequest } from "@/lib/msalConfig";
import { ThemeProvider } from "@/components/ThemeProvider";
import { SyncProvider } from "@/context/SyncContext";
import { EventType } from "@azure/msal-browser";

export function Providers({ children }: { children: React.ReactNode }) {
 const [initialized, setInitialized] = useState(false);
 const msalInstance = getMsalInstance();
 const initRef = useRef(false);

 useEffect(() => {
 if (initRef.current) return;
 initRef.current = true;

 const initializeMsal = async () => {
 try {
 console.log("MSAL: Initializing instance...");
 await msalInstance.initialize();
 
 // Handle redirect promise (important for both redirect and catching popup response)
 const result = await msalInstance.handleRedirectPromise();
 console.log("MSAL: Redirect promise handled.", result);

 if (result && result.account) {
 msalInstance.setActiveAccount(result.account);
 } else {
 const accounts = msalInstance.getAllAccounts();
 if (accounts.length > 0 && !msalInstance.getActiveAccount()) {
 msalInstance.setActiveAccount(accounts[0]);
 }
 }

 // Add event callback for future login/logout events
 msalInstance.addEventCallback((event) => {
 if ((event.eventType === EventType.LOGIN_SUCCESS || event.eventType === EventType.ACQUIRE_TOKEN_SUCCESS) && event.payload) {
 const payload = event.payload as any;
 const account = payload.account;
 if (account) {
 msalInstance.setActiveAccount(account);
 }
 }
 });

 console.log("MSAL: Initialization complete.");
 } catch (err) {
 console.error("MSAL: Initialization failed:", err);
 } finally {
 setInitialized(true);
 }
 };

 initializeMsal();
 }, [msalInstance]);

 if (!initialized) {
 return (
 <div className="fixed inset-0 flex items-center justify-center bg-[#0a0a0a] z-[9999]">
 <div className="w-8 h-8 border-2 border-white/20 border-t-white rounded-full animate-spin" />
 <span className="ml-4 text-white/50 text-xs font-mono uppercase">Initializing Secure OS...</span>
 </div>
 );
 }

 return (
 <ThemeProvider
 attribute="data-theme"
 defaultTheme="system"
 enableSystem
 disableTransitionOnChange
 >
 <MsalProvider instance={msalInstance}>
 <SyncProvider>
 {children}
 </SyncProvider>
 </MsalProvider>
 </ThemeProvider>
 );
}

"use client";

import React from 'react';

interface SyncStatusProps {
 status: 'idle' | 'syncing' | 'error' | 'unauthenticated' | 'connected' | 'initializing' | 'local';
 isDevelopment?: boolean;
}

export function SyncStatus({ status, isDevelopment }: SyncStatusProps) {
 const getStatusConfig = () => {
 switch (status) {
 case 'syncing':
 return { 
 color: 'bg-amber-500', 
 text: 'Syncing...', 
 ping: true,
 label: 'text-amber-600 dark:text-amber-400'
 };
 case 'connected':
 return { 
 color: 'bg-emerald-500', 
 text: isDevelopment ? 'Cloud Active (Pull Only)' : 'Cloud Active', 
 ping: false,
 label: 'text-emerald-600 dark:text-emerald-400'
 };
 case 'error':
 return { 
 color: 'bg-rose-500', 
 text: 'Sync Error', 
 ping: false,
 label: 'text-rose-600 dark:text-rose-400'
 };
 case 'unauthenticated':
 return { 
 color: 'bg-zinc-400', 
 text: 'Offline (Local Only)', 
 ping: false,
 label: 'text-zinc-500 dark:text-zinc-400'
 };
 case 'initializing':
 return { 
 color: 'bg-blue-500', 
 text: 'Initializing...', 
 ping: true,
 label: 'text-blue-600 dark:text-blue-400'
 };
 case 'local':
 return { 
 color: 'bg-indigo-400', 
 text: 'Sync Isolated (Local)', 
 ping: false,
 label: 'text-indigo-600 dark:text-indigo-400'
 };
 default:
 return { 
 color: 'bg-emerald-500/50', 
 text: isDevelopment ? 'Cloud Synced (Isolated)' : 'Cloud Synced', 
 ping: false,
 label: 'text-zinc-400 dark:text-zinc-500'
 };
 }
 };

 const config = getStatusConfig();

 return (
 <div className="flex items-center gap-2 px-3 py-1.5 rounded-full bg-zinc-100/50 dark:bg-zinc-800/30 border border-zinc-200/50 dark:border-zinc-700/30 transition-all duration-500">
 <div className="relative flex h-2 w-2">
 {config.ping && (
 <span className={`animate-ping absolute inline-flex h-full w-full rounded-full ${config.color} opacity-75`}></span>
 )}
 <span className={`relative inline-flex rounded-full h-2 w-2 ${config.color}`}></span>
 </div>
 <span className={`text-xs font-semibold uppercase ${config.label} transition-colors duration-500`}>
 {config.text}
 </span>
 </div>
 );
}

