"use client";

import React, { useEffect, useState } from "react";
import { useTheme } from "next-themes";
import { Sun, Moon } from "lucide-react";

export function ThemeToggle() {
 const { theme, setTheme, resolvedTheme } = useTheme();
 const [mounted, setMounted] = useState(false);

 // Avoid hydration mismatch by only rendering after mount
 useEffect(() => {
 setMounted(true);
 }, []);

 if (!mounted) {
 return (
 <div className="w-10 h-10 rounded-xl bg-white/50 dark:bg-zinc-900/50 backdrop-blur-xl border border-zinc-200/50 dark:border-zinc-800/50 animate-pulse" />
 );
 }

 const isDark = resolvedTheme === "dark";

 return (
 <button
 onClick={() => setTheme(isDark ? "light" : "dark")}
 className="flex items-center justify-center gap-2 px-4 py-2 rounded-2xl bg-white/50 dark:bg-zinc-900/50 backdrop-blur-xl border border-zinc-200/50 dark:border-zinc-800/50 text-zinc-500 hover:text-zinc-900 dark:text-zinc-400 dark:hover:text-white transition-all duration-300 group shadow-sm hover:shadow-md"
 aria-label="Toggle theme"
 >
 <div className="relative w-5 h-5">
 <Sun 
 className={`absolute inset-0 transition-all duration-500 transform ${ isDark ? "rotate-90 scale-0 opacity-0" : "rotate-0 scale-100 opacity-100" } text-amber-500`} 
 size={20} 
 />
 <Moon 
 className={`absolute inset-0 transition-all duration-500 transform ${ isDark ? "rotate-0 scale-100 opacity-100" : "-rotate-90 scale-0 opacity-0" } text-indigo-400`} 
 size={20} 
 />
 </div>
 <span className="text-xs font-semibold uppercase">
 {isDark ? 'Dark Mode' : 'Light Mode'}
 </span>
 </button>
 );
}

"use client";

import React, { useState } from 'react';
import type { Book } from '@/types/books';
import { BOOK_CATEGORIES } from '@/types/books';
import { Modal } from '../ui/Modal';
import { DynamicForm } from '../ui/DynamicForm';

interface BookModalProps {
 book: Book;
 onClose: () => void;
 onUpdateBook: (updatedBook: Book) => void;
 onDeleteBook: (bookId: string) => void;
 mode?: 'edit' | 'create';
}

export function BookModal({ book, onClose, onUpdateBook, onDeleteBook, mode = 'edit' }: BookModalProps) {
 const [formData, setFormData] = useState({
 name: book.name || '',
 author: book.author || '',
