 {new Date(book.completionDate).toLocaleDateString(undefined, { month: 'short', day: 'numeric', year: 'numeric' })}
 </Text>
 <Text variant="label" as="span" className="flex items-center gap-1.5 font-semibold whitespace-nowrap">
