 <Text 
 variant="label"
 as="div"
 className={`px-3 py-1.5 rounded-full font-bold border flex items-center gap-1.5 transition-colors ${ book.wouldRecommend ? 'bg-teal-50 dark:bg-teal-500/10 text-teal-600 dark:text-teal-400 border-teal-100 dark:border-teal-500/20' : 'bg-zinc-50 dark:bg-zinc-500/10 text-zinc-600 dark:text-zinc-400 border-zinc-100 dark:border-zinc-500/20' }`}
 >
 {book.wouldRecommend ? <ThumbsUp size={12} /> : <ThumbsDown size={12} />}
 {book.wouldRecommend ? 'Highly Recommended' : 'Mixed Opinion'}
 </Text>
 </div>
 );
 }

 return (
 <div 
 onClick={onEdit}
