 >
 {/* Visual Accent */}
 <div className="absolute top-0 right-0 w-32 h-32 bg-teal-500/5 -mr-16 -mt-16 rounded-full group-hover:scale-150 transition-transform duration-700"></div>

 <div className="flex flex-col gap-5 relative z-10">
 {/* Header: Name & Rating */}
 <div className="flex justify-between items-start gap-4">
 <div className="flex-1 min-w-0">
 <div className="flex items-center gap-2 mb-1.5">
 <Text variant="label" as="span" className="font-semibold opacity-60">{book.language}</Text>
 <Text variant="label" as="span" className="font-semibold text-teal-600 dark:text-teal-400 opacity-80 flex items-center gap-1">
 <Tag size={10} />
 {book.category || 'Other'}
 </Text>
 {book.wouldRecommend && <ThumbsUp size={10} className="text-teal-500" />}
 </div>
 <Text variant="title" as="h4" className="text-2xl leading-tight group-hover:text-teal-600 dark:group-hover:text-teal-400 transition-colors">
 {book.name}
 </Text>
 <Text variant="label" as="div" className="font-semibold mt-2">
 {book.author || 'Unknown Author'}
 </Text>
 </div>
 <div className="flex flex-col items-end gap-1">
 <div className="flex gap-0.5">
 {[...Array(5)].map((_, i) => (
 <Star 
 key={i} 
 size={12} 
 className={i < book.rating ? "text-amber-500" : "text-zinc-200 dark:text-zinc-800"} 
 fill={i < book.rating ? "currentColor" : "none"} 
 />
 ))}
 </div>
 </div>
 </div>

 <div className="h-px bg-zinc-100 dark:bg-zinc-800 w-full"></div>

 {/* Notes Preview */}
 <div className="relative">
 <Quote className="absolute -left-2 -top-2 text-teal-500/10 dark:text-teal-500/5 rotate-180" size={32} />
 <Text variant="body" as="p" className="text-sm font-medium line-clamp-3 leading-relaxed italic">
 "{book.notes || 'No notes captured yet...'}"
 </Text>
 </div>

 <div className="mt-auto flex items-center justify-between pt-2">
 <Text variant="label" as="div" className="font-semibold flex items-center gap-2">
 <Calendar size={12} className="opacity-40" />
 {new Date(book.completionDate).toLocaleDateString(undefined, { month: 'short', day: 'numeric', year: 'numeric' })}
 </Text>
 <Text variant="label" as="div" className={`px-3 py-1 rounded-full font-semibold ${ book.wouldRecommend ? 'bg-teal-50 dark:bg-teal-500/10 text-teal-600' : 'bg-zinc-100 dark:bg-zinc-800 text-zinc-500' }`}>
 {book.wouldRecommend ? 'Highly Recommended' : 'Completed'}
 </Text>
 </div>
 </div>
 </div>
 );
}

function StatCard({ icon, value, description }: { icon: React.ReactNode, value: string, description: string }) {
 return (
 <div className="bg-white dark:bg-zinc-950 border-2 border-zinc-50 dark:border-zinc-900 p-6 rounded-2xl flex items-center gap-6 shadow-sm hover:border-teal-500/10 transition-all duration-300 group relative overflow-hidden">
 <div className="w-14 h-14 bg-zinc-50 dark:bg-zinc-900 rounded-2xl flex items-center justify-center shadow-inner shrink-0 group-hover:scale-105 transition-transform duration-500">
 {icon}
 </div>

 <div className="flex-1 min-w-0 flex items-center justify-between gap-4">
 <Text variant="body" as="h4" className="text-xl font-semibold leading-none truncate group-hover:text-teal-600 dark:group-hover:text-teal-400 transition-colors">
 {description}
 </Text>
 <Text variant="title" as="p" className="text-3xl shrink-0 tabular-nums">
 {value}
 </Text>
 </div>
 
 {/* Subtle border accent */}
 <div className="absolute right-0 top-0 h-full w-1.5 bg-zinc-50 dark:bg-zinc-900 group-hover:bg-teal-500/20 transition-colors"></div>
 </div>
 );
}

