 >
 Settings
 </button>
 <button 
 onClick={() => setIsContributionModalOpen(true)}
 className="bg-amber-500 text-white text-xs px-5 sm:px-8 py-2.5 sm:py-3.5 rounded-2xl hover:scale-105 active:scale-95 transition-all shadow-sm dark:shadow-none font-semibold"
 >
 Log
 </button>
 </div>
 </div>

 <div className="bg-white dark:bg-zinc-900/60 border border-l-4 border-amber-100/50 dark:border-amber-900/30 rounded-2xl p-4 sm:p-6 lg:p-8 shadow-sm transition-all duration-500 relative overflow-hidden group">
