 >
 {isCollapsed ? (
 <ChevronRight className="w-5 h-5 text-zinc-400 group-hover:text-zinc-600 dark:group-hover:text-zinc-300" />
 ) : (
 <ChevronDown className="w-5 h-5 text-zinc-400 group-hover:text-zinc-600 dark:group-hover:text-zinc-300" />
 )}
 </button>
 </div>
 
 <div className="flex flex-wrap items-center gap-4">
 <div className="flex gap-3">
 <MultiSelectDropdown 
 label="Month" 
 options={MONTHS} 
 selected={selectedMonths} 
 onChange={setSelectedMonths} 
 />
 <MultiSelectDropdown 
 label="Year" 
 options={YEARS} 
 selected={selectedYears} 
 onChange={setSelectedYears} 
 />
 </div>
 <button 
 onClick={openAddModal}
 className="bg-rose-600 text-white text-xs px-8 py-4 rounded-2xl hover:scale-105 active:scale-95 transition-all shadow-xl shadow-rose-200/50 dark:shadow-none h-[54px] font-semibold"
 >
 Add Expense
 </button>
 </div>
 </div>

 <div className="flex flex-col gap-10">
 {/* Top Row: Metrics Integrated into the main flow */}
 {!isCollapsed && (
 <div className="flex flex-col gap-10 animate-in fade-in slide-in-from-top-4 duration-300">
 <ExpenseMetrics records={records} selectedMonths={selectedMonths} selectedYears={selectedYears} />

 {/* Category Breakdown */}
 {filteredRecords.length > 0 && (
 <div className="flex flex-col gap-4">
 <Text variant="label" as="span" className="pl-4">Category Breakdown</Text>
 <div className="grid grid-cols-2 md:grid-cols-4 lg:grid-cols-6 gap-4 px-2">
