 <Text variant="label" as="span" className="mb-1">{cat}</Text>
 <Text variant="title" as="span" className="text-lg leading-tight">${total.toLocaleString('en-CA', {maximumFractionDigits: 0})}</Text>
 </div>
 ))}
 </div>
 </div>
 )}
 </div>
 )}

 {/* Table Section */}
 <div className="bg-white dark:bg-zinc-900/60 border border-l-4 border-rose-100 dark:border-rose-900/30 rounded-2xl p-2 overflow-hidden shadow-sm transition-all flex flex-col pt-8">
 <div className="flex items-center justify-between px-8 mb-8">
 <Text variant="label" as="span">Detailed Records</Text>
 </div>

 <div className="overflow-x-auto px-4">
 <table className="w-full text-left border-collapse min-w-[800px]">
 <thead>
 <tr className="border-b border-zinc-50 dark:border-zinc-800/50">
 <Text variant="label" as="th" className="px-4 py-4 font-semibold uppercase">Date</Text>
 <Text variant="label" as="th" className="px-4 py-4 font-semibold uppercase">Category</Text>
 <Text variant="label" as="th" className="px-4 py-4 font-semibold uppercase">Subcategory</Text>
 <Text variant="label" as="th" className="px-4 py-4 font-semibold uppercase">Type</Text>
 <Text variant="label" as="th" className="px-4 py-4 font-semibold uppercase">Paid from</Text>
 <Text variant="label" as="th" className="px-4 py-4 font-semibold uppercase">Paid to</Text>
 <Text variant="label" as="th" className="px-4 py-4 font-semibold uppercase">Notes</Text>
 <Text variant="label" as="th" className="px-4 py-4 font-semibold uppercase text-right">Amount</Text>
 <th className="px-4 py-4 text-xs font-semibold uppercase text-zinc-600 dark:text-zinc-300"></th>
 </tr>
 </thead>
 <tbody>
 {filteredRecords.length > 0 ? filteredRecords.map(record => (
 <tr key={record.id} className="group hover:bg-zinc-50 dark:hover:bg-zinc-800/30 transition-colors border-b border-zinc-50 dark:border-zinc-800/20 last:border-0">
 <td className="px-4 py-5">
 <Text variant="bodySmall" muted as="span" className="text-xs">

 {new Date(record.date).toLocaleDateString('en-IN', { month: 'short', day: 'numeric', year: 'numeric' })}
 </Text>
 </td>
 <td className="px-4 py-5">
 <Text variant="body" as="span" className="font-semibold">
 {record.category}
 </Text>
 </td>
 <td className="px-4 py-5">
 <Text variant="bodySmall" muted as="span" className="text-xs">

 {record.subcategory || '-'}
 </Text>
 </td>
 <td className="px-4 py-5">
 <Text variant="label" as="span" className="px-2.5 py-1 rounded-lg border bg-rose-50 text-rose-600 border-rose-100 dark:bg-rose-500/10 dark:text-rose-400">
 {record.type}
 </Text>
 </td>
 <td className="px-4 py-5">
 <Text variant="bodySmall" muted as="span" className="text-xs">

 {assets.find(a => a.id === record.assetId)?.name || '-'}
 </Text>
 </td>
 <td className="px-4 py-5">
 <Text variant="bodySmall" muted as="span" className="text-xs">

 {record.paidToType === 'other' 
 ? record.paidToName || '-' 
 : record.paidToType === 'emergency'
 ? 'Emergency Fund'
 : record.paidToType === 'savings'
 ? (savingsGoals.find(g => g.id === record.paidToId)?.name || 'Savings Goal')
 : record.paidToType === 'asset'
 ? (assets.find(a => a.id === record.paidToId)?.name || 'Asset')
 : record.paidToType === 'liability'
 ? (liabilities.find(l => l.id === record.paidToId)?.name || 'Liability')
 : '-'}
 </Text>
 </td>
 <td className="px-4 py-5 max-w-[150px]">
 <Text variant="bodySmall" muted as="span" className="text-xs truncate block">

 {record.notes || '-'}
 </Text>
 </td>
 <td className="px-4 py-5 text-right">
 <Text variant="body" as="span" className="font-semibold">${record.amount.toLocaleString("en-CA", { minimumFractionDigits: 2 })}</Text>
 </td>
 <td className="px-4 py-5 text-right">
 <button 
