"use client";

import React, { useState, useEffect } from 'react';
import { Wallet, Shield, TrendingUp, TrendingDown, Percent, ChevronDown, ChevronRight } from 'lucide-react';
import { getPrefixedKey } from '@/lib/keys';
import { MultiSelectDropdown } from '../ui/MultiSelectDropdown';
import { MONTHS, YEARS } from '@/lib/constants';
import { calculateAssetBalance, calculateLiabilityBalance, type Asset, type Liability } from '@/lib/finances';
import { SYNC_KEYS } from '@/lib/sync-keys';
import { Text, SectionTitle } from '../ui/Text';

interface MetricProps {
  label: string;
  value: string;
  subValue?: string;
  icon: React.ReactNode;
  color: 'teal' | 'emerald' | 'rose' | 'amber' | 'indigo' | 'blue';
  customBg?: string;
}

function MetricCard({ label, value, subValue, icon, color, customBg }: MetricProps) {
  const iconClasses = {
    teal: "bg-teal-50 text-teal-600 dark:bg-teal-500/10 dark:text-teal-400",
    emerald: "bg-emerald-50 text-emerald-600 dark:bg-emerald-500/10 dark:text-emerald-400",
    rose: "bg-rose-50 text-rose-600 dark:bg-rose-500/10 dark:text-rose-400",
    amber: "bg-amber-50 text-amber-600 dark:bg-amber-500/10 dark:text-amber-400",
    indigo: "bg-indigo-50 text-indigo-600 dark:bg-indigo-500/10 dark:text-indigo-400",
    blue: "bg-blue-50 text-blue-600 dark:bg-blue-500/10 dark:text-blue-400",
  };

  const borderClasses = {
    teal: "border-teal-100/50 dark:border-teal-900/30",
    emerald: "border-emerald-100/50 dark:border-emerald-900/30",
    rose: "border-rose-100/50 dark:border-rose-900/30",
    amber: "border-amber-100/50 dark:border-amber-900/30",
    indigo: "border-indigo-100/50 dark:border-indigo-900/30",
    blue: "border-blue-100/50 dark:border-blue-900/30",
  };

  return (
    <div className={`flex flex-col p-4 md:p-6 rounded-2xl border border-l-4 shadow-sm transition-all group relative overflow-hidden h-full bg-white dark:bg-zinc-900/60 ${customBg || borderClasses[color]}`}>
      <div className="flex items-center justify-between mb-4 md:mb-6">
        <div className={`p-2.5 md:p-3.5 rounded-2xl transition-colors ${iconClasses[color]}`}>
          {React.cloneElement(icon as React.ReactElement<any>, { className: "w-5 h-5 md:w-6 md:h-6" })}
        </div>
        {subValue && (
          <div className="flex flex-col items-end">
            <Text variant="label" as="span" className="bg-zinc-50 dark:bg-zinc-800/50 px-2.5 py-1 rounded-full text-right leading-none">
              {subValue}
            </Text>
          </div>
        )}
      </div>

      <div className="flex flex-col gap-0.5">
        <Text variant="label" as="span" className="mb-0.5">
          {label}
        </Text>
        <div className="flex flex-col">
          <Text variant="metric" as="span" className="text-xl md:text-2xl leading-none">
            {value}
          </Text>
        </div>
      </div>
    </div>
  );
}

interface EmergencyFundData {
  targetAmount: number;
  monthlyExpenses: number;
  contributions: { id: string; amount: number }[];
}

export function FinanceOverview() {
  const [income, setIncome] = useState(0);
  const [expenses, setExpenses] = useState(0);
  const [netWorth, setNetWorth] = useState(0);
  const [emergencyFundMonths, setEmergencyFundMonths] = useState(0);
  const [isLoaded, setIsLoaded] = useState(false);
  const [isCollapsed, setIsCollapsed] = useState(false);

  // Filter states
  const [selectedMonths, setSelectedMonths] = useState<number[]>([]); // Initialize empty for SSR
  const [selectedYears, setSelectedYears] = useState<number[]>([]);

  const calculateFinance = () => {
    // 1. Calculate Income
    const incomeData = localStorage.getItem(getPrefixedKey(SYNC_KEYS.FINANCES_INCOME));
    let totalIncomeCount = 0;
    if (incomeData) {
      try {
        const records = JSON.parse(incomeData);
        totalIncomeCount = records
          .filter((r: any) => {
            const d = new Date(r.date);
            return selectedMonths.includes(d.getMonth()) && selectedYears.includes(d.getFullYear());
          })
          .reduce((sum: number, r: any) => sum + r.amount, 0);
      } catch (e) { console.error("Error parsing block:", e); }
    }
    setIncome(totalIncomeCount);

    // 2. Calculate Expenses
    const expenseData = localStorage.getItem(getPrefixedKey(SYNC_KEYS.FINANCES_EXPENSES));
    let totalExpensesCount = 0;
    if (expenseData) {
      try {
        const records = JSON.parse(expenseData);
        totalExpensesCount = records
          .filter((r: any) => {
            const d = new Date(r.date);
            return selectedMonths.includes(d.getMonth()) && selectedYears.includes(d.getFullYear());
          })
          .reduce((sum: number, r: any) => sum + r.amount, 0);
      } catch (e) { console.error("Error parsing block:", e); }
    }
    setExpenses(totalExpensesCount);

    // 3. Calculate Net Worth
    let totalAssets = 0;
    const assetsData = localStorage.getItem(getPrefixedKey(SYNC_KEYS.FINANCES_ASSETS));
    if (assetsData) {
      try {
        const assets: Asset[] = JSON.parse(assetsData);
        totalAssets = assets.reduce((sum, a) => sum + calculateAssetBalance(a), 0);
      } catch (e) { console.error("Error parsing block:", e); }
    }

    let totalLiabilities = 0;
    const liabilitiesData = localStorage.getItem(getPrefixedKey(SYNC_KEYS.FINANCES_LIABILITIES));
    if (liabilitiesData) {
      try {
        const liabilities: Liability[] = JSON.parse(liabilitiesData);
        totalLiabilities = liabilities.reduce((sum, l) => sum + calculateLiabilityBalance(l), 0);
      } catch (e) { console.error("Error parsing block:", e); }
    }
    setNetWorth(totalAssets - totalLiabilities);

    // 4. Calculate Emergency Fund
    const efData = localStorage.getItem(getPrefixedKey(SYNC_KEYS.FINANCES_EMERGENCY_FUND));
    let monthsCovered = 0;
    if (efData) {
      try {
        const data: EmergencyFundData = JSON.parse(efData);
        const totalSaved = data.contributions.reduce((sum, c) => sum + c.amount, 0);
        monthsCovered = data.monthlyExpenses > 0 ? totalSaved / data.monthlyExpenses : 0;
      } catch (e) { console.error("Error parsing block:", e); }
    }
    setEmergencyFundMonths(monthsCovered);
  };

  useEffect(() => {
    setSelectedMonths([new Date().getMonth()]);
    setSelectedYears([new Date().getFullYear()]);
    setIsLoaded(true);
  }, []);

  useEffect(() => {
    if (isLoaded) {
      calculateFinance();
    }

    const handleLocal = (e: any) => {
      if (e.detail && [
        SYNC_KEYS.FINANCES_INCOME, 
        SYNC_KEYS.FINANCES_EXPENSES, 
        SYNC_KEYS.FINANCES_ASSETS, 
        SYNC_KEYS.FINANCES_LIABILITIES, 
        SYNC_KEYS.FINANCES_EMERGENCY_FUND,
      ].includes(e.detail.key)) {
        calculateFinance();
      }
    };

    window.addEventListener('local-storage-change', handleLocal);
    return () => window.removeEventListener('local-storage-change', handleLocal);
  }, [selectedMonths, selectedYears, isLoaded]);

  if (!isLoaded) return null;

  const savingsRate = income > 0 ? ((income - expenses) / income) * 100 : 0;

  return (
    <div className="w-full flex flex-col gap-6 md:gap-8">
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-4 md:gap-6 px-1 md:px-2">
        <div className="flex items-center gap-2 group cursor-pointer" onClick={() => setIsCollapsed(!isCollapsed)}>
          <SectionTitle>
            Financial Overview
          </SectionTitle>
          <button 
            className="p-1.5 rounded-xl hover:bg-zinc-100 dark:hover:bg-zinc-800 transition-colors"
            aria-label={isCollapsed ? "Expand section" : "Collapse section"}
          >
            {isCollapsed ? (
              <ChevronRight className="w-5 h-5 text-zinc-400 group-hover:text-zinc-600 dark:group-hover:text-zinc-300" />
            ) : (
              <ChevronDown className="w-5 h-5 text-zinc-400 group-hover:text-zinc-600 dark:group-hover:text-zinc-300" />
            )}
          </button>
        </div>

        <div className="flex gap-2 md:gap-3">
          <MultiSelectDropdown
            label="Month"
            options={MONTHS}
            selected={selectedMonths}
            onChange={setSelectedMonths}
          />
          <MultiSelectDropdown
            label="Year"
            options={YEARS}
            selected={selectedYears}
            onChange={setSelectedYears}
          />
        </div>
      </div>

      {!isCollapsed && (
        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 xl:grid-cols-5 gap-3 md:gap-6 animate-in fade-in slide-in-from-top-4 duration-300">
          <MetricCard 
            label="Net Worth"
            value={`$${netWorth.toLocaleString("en-CA", { maximumFractionDigits: 0 })}`}
            subValue={netWorth >= 0 ? "Positive Equity" : "Negative Equity"}
            color={netWorth >= 0 ? "emerald" : "rose"}
            customBg={netWorth >= 0 
              ? "border-emerald-100/50 dark:border-emerald-900/30" 
              : "border-rose-100/50 dark:border-rose-900/30"
            }
            icon={<Wallet strokeWidth={2.5} />}
          />

          <MetricCard 
            label="Emergency Fund"
            value={`${emergencyFundMonths < 10 ? emergencyFundMonths.toFixed(1) : Math.floor(emergencyFundMonths)} Months`}
            subValue={emergencyFundMonths >= 6 ? "Fully Funded" : emergencyFundMonths >= 3 ? "On Track" : "Focus Needed"}
            color={emergencyFundMonths >= 6 ? "emerald" : emergencyFundMonths >= 3 ? "amber" : "rose"}
            customBg={emergencyFundMonths >= 6 
              ? "border-emerald-100/50 dark:border-emerald-900/30"
              : emergencyFundMonths >= 3
              ? "border-amber-100/50 dark:border-amber-900/30"
              : "border-rose-100/50 dark:border-rose-900/30"
            }
            icon={<Shield strokeWidth={2.5} />}
          />

          <MetricCard
            label="Monthly Income"
            value={`$${income.toLocaleString("en-CA", { maximumFractionDigits: 0 })}`}
            subValue={selectedMonths.length === 1 && selectedYears.length === 1 ? MONTHS[selectedMonths[0]] : `${selectedMonths.length} Months`}
            color="emerald"
            icon={<TrendingUp strokeWidth={2.5} />}
          />

          <MetricCard
            label="Monthly Expenses"
            value={`$${expenses.toLocaleString("en-CA", { maximumFractionDigits: 0 })}`}
            subValue={`${income > 0 ? ((expenses / income) * 100).toFixed(0) : 0}% of Income`}
            color="rose"
            icon={<TrendingDown strokeWidth={2.5} />}
          />

          <MetricCard
            label="Savings Rate"
            value={`${savingsRate.toFixed(1)}%`}
            subValue="Goal: 20%"
            color={savingsRate >= 20 ? "emerald" : savingsRate >= 10 ? "amber" : "rose"}
            customBg={savingsRate >= 20
              ? "border-emerald-100/50 dark:border-emerald-900/30"
              : savingsRate >= 10
              ? "border-amber-100/50 dark:border-amber-900/30"
              : "border-rose-100/50 dark:border-rose-900/30"
            }
            icon={<Percent strokeWidth={2.5} />}
          />
        </div>
      )}
    </div>
  );
}

"use client";

import { type IncomeRecord } from '@/lib/finances';
import { MONTHS } from '@/lib/constants';


interface IncomeMetricsProps {
 records: IncomeRecord[];
 selectedMonths: number[];
 selectedYears: number[];
}

interface MetricProps {
 label: string;
 value: string;
 subValue?: string;
 icon: React.ReactNode;
 color: 'teal' | 'emerald' | 'amber' | 'indigo' | 'blue';
}

function MetricCard({ label, value, subValue, icon, color }: MetricProps) {
 const iconClasses = {
 teal: "bg-teal-100 text-teal-600 dark:bg-teal-500/20 dark:text-teal-300",
 emerald: "bg-emerald-100 text-emerald-600 dark:bg-emerald-500/20 dark:text-emerald-300",
 amber: "bg-amber-100 text-amber-600 dark:bg-amber-500/20 dark:text-amber-300",
 indigo: "bg-indigo-100 text-indigo-600 dark:bg-indigo-500/20 dark:text-indigo-300",
 blue: "bg-blue-100 text-blue-600 dark:bg-blue-500/20 dark:text-blue-300",
 };

 return (
 <div className="flex flex-col p-6 rounded-2xl border border-l-4 border-emerald-100 dark:border-emerald-900/30 bg-white dark:bg-zinc-900/60 shadow-sm transition-all group relative overflow-hidden h-full">
 <div className="flex items-center justify-between mb-6">
 <div className={`p-3.5 rounded-2xl transition-colors ${iconClasses[color]}`}>
 {icon}
 </div>
 {subValue && (
 <div className="flex flex-col items-end">
 <span className="text-xs uppercase text-zinc-600 dark:text-zinc-400 bg-zinc-50 dark:bg-zinc-800/50 px-3 py-1.5 rounded-xl text-right font-semibold">
 {subValue}
 </span>
 </div>
 )}
 </div>
 
 <div className="flex flex-col gap-1">
 <span className="text-xs uppercase text-zinc-500 dark:text-zinc-400 mb-1 font-semibold">
 {label}
 </span>
 <div className="flex flex-col">
 <span className="text-2xl text-zinc-900 dark:text-zinc-100 leading-none font-bold">
 {value}
 </span>
 </div>
 </div>
 </div>
 );
}

export function IncomeMetrics({ records, selectedMonths, selectedYears }: IncomeMetricsProps) {
 const filteredRecords = records.filter(r => {
 const d = new Date(r.date);
 return selectedMonths.includes(d.getMonth()) && selectedYears.includes(d.getFullYear());
 });

 // Calculate totals
 const totalIncome = filteredRecords.reduce((sum, r) => sum + r.amount, 0);

 const typeTotals = {
 active: filteredRecords.filter(r => r.type === 'active').reduce((sum, r) => sum + r.amount, 0),
 passive: filteredRecords.filter(r => r.type === 'passive').reduce((sum, r) => sum + r.amount, 0),
 'one time': filteredRecords.filter(r => r.type === 'one time').reduce((sum, r) => sum + r.amount, 0),
 };

 const activePct = totalIncome > 0 ? (typeTotals.active / totalIncome) * 100 : 0;
 const passivePct = totalIncome > 0 ? (typeTotals.passive / totalIncome) * 100 : 0;
 const oneTimePct = totalIncome > 0 ? (typeTotals['one time'] / totalIncome) * 100 : 0;

 // Find Top Source
 const sourceTotals: Record<string, number> = {};
 filteredRecords.forEach(r => {
 sourceTotals[r.source] = (sourceTotals[r.source] || 0) + r.amount;
 });
 const topSourceEntry = Object.entries(sourceTotals).sort((a, b) => b[1] - a[1])[0];
 const topSourceStr = topSourceEntry ? `${topSourceEntry[0]}` : 'None';
 const topSourceVal = topSourceEntry ? topSourceEntry[1] : 0;

 const selectionLabel = selectedMonths.length === 1 && selectedYears.length === 1 ? MONTHS[selectedMonths[0]] : `${selectedMonths.length} Months`;

 return (
 <div className="grid grid-cols-2 sm:grid-cols-2 lg:grid-cols-5 gap-6">
 <MetricCard 
 label="Total Income"
 value={`$${totalIncome.toLocaleString('en-CA', { maximumFractionDigits: 0 })}`}
 subValue={selectionLabel}
 color="emerald"
 icon={<svg className="w-5 h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M12 8c-1.657 0-3 1.343-3 3s1.343 3 3 3 3 1.343 3 3-1.343 3-3 3m0-12c-1.657 0-3-1.343-3-3s1.343-3 3-3 3 1.343 3 3-1.343 3-3 3m0 12v1m0-18v1" /></svg>}
 />

 <MetricCard 
 label="Active Income"
 value={`$${typeTotals.active.toLocaleString('en-CA', { maximumFractionDigits: 0 })}`}
 subValue={`${activePct.toFixed(0)}% Total`}
 color="emerald"
 icon={<svg className="w-5 h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M21 13.255A23.931 23.931 0 0112 15c-3.183 0-6.22-.62-9-1.745M16 6V4a2 2 0 00-2-2h-4a2 2 0 00-2 2v2m4 6h.01M5 20h14a2 2 0 002-2V8a2 2 0 00-2-2H5a2 2 0 00-2 2v10a2 2 0 002 2z" /></svg>}
 />

 <MetricCard 
 label="Passive Income"
 value={`$${typeTotals.passive.toLocaleString('en-CA', { maximumFractionDigits: 0 })}`}
 subValue={`${passivePct.toFixed(0)}% Total`}
 color="emerald"
 icon={<svg className="w-5 h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M13 7h8m0 0v8m0-8l-8 8-4-4-6 6" /></svg>}
 />

 <MetricCard 
 label="One-Time"
 value={`$${typeTotals['one time'].toLocaleString('en-CA', { maximumFractionDigits: 0 })}`}
 subValue={`${oneTimePct.toFixed(0)}% Total`}
 color="emerald"
 icon={<svg className="w-5 h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M12 8v4l3 2m6-2a9 9 0 11-18 0 9 9 0 0118 0z" /></svg>}
 />

 <MetricCard 
 label="Top Source"
 value={topSourceStr.charAt(0).toUpperCase() + topSourceStr.slice(1)}
 subValue={`$${topSourceVal.toLocaleString('en-CA', { maximumFractionDigits: 0 })}`}
 color="emerald"
 icon={<svg className="w-5 h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M19 21V5a2 2 0 00-2-2H7a2 2 0 00-2 2v16m14 0h2m-2 0h-5m-9 0H3m2 0h5M9 7h1m-1 4h1m4-4h1m-1 4h1m-5 10v-5a1 1 0 011-1h2a1 1 0 011 1v5m-4 0h4" /></svg>}
 />
 </div>
 );
}

