import React, { useState, useEffect, useRef } from 'react';
import { getPrefixedKey } from '@/lib/keys';
import { setSyncedItem } from '@/lib/storage';
import { Modal } from '../ui/Modal';
import { DynamicForm } from '../ui/DynamicForm';
import { calculateAssetBalance } from '@/lib/finances';
import { SYNC_KEYS } from '@/lib/sync-keys';
import { SectionTitle } from '../ui/Text';
import { LayoutGrid, List } from 'lucide-react';


interface Contribution {
 id: string;
 date: string;
 amount: number;
}

interface SavingsGoal {
 id: string;
 name: string;
 targetAmount: number;
 initialAmount: number;
 startDate: string;
 targetDate: string;
 contributions: Contribution[];
}

export function SavingsTargets() {
 const [goals, setGoals] = useState<SavingsGoal[]>([]);
 const [isLoaded, setIsLoaded] = useState(false);
 const [isGoalModalOpen, setIsGoalModalOpen] = useState(false);
 const [editingGoal, setEditingGoal] = useState<SavingsGoal | null>(null);
 
 // Contribution modal state
 const [isContributionModalOpen, setIsContributionModalOpen] = useState(false);
 const [targetGoalId, setTargetGoalId] = useState<string | null>(null);
 const [contributionAmount, setContributionAmount] = useState('');

 // History modal state
 const [isHistoryModalOpen, setIsHistoryModalOpen] = useState(false);
 const [historyGoalId, setHistoryGoalId] = useState<string | null>(null);
 const [expandedGoals, setExpandedGoals] = useState<Record<string, boolean>>({});

  const [viewMode, setViewMode] = useState<'grid' | 'table'>('grid');

  useEffect(() => {
    const savedView = localStorage.getItem('finances-savings-view');
    if (savedView === 'table' || savedView === 'grid') setViewMode(savedView);
  }, []);

  const toggleViewMode = (mode: 'grid' | 'table') => {
    setViewMode(mode);
    localStorage.setItem('finances-savings-view', mode);
  };

  const toggleExpand = (id: string) => {
 setExpandedGoals(prev => ({ ...prev, [id]: !prev[id] }));
 };

 // Form states
 const [formData, setFormData] = useState({
 name: '',
 targetAmount: '',
 initialAmount: '',
 startDate: '',
 targetDate: ''
 });

 const goalsRef = useRef(goals);
 useEffect(() => {
 goalsRef.current = goals;
 }, [goals]);

 useEffect(() => {
 const saved = localStorage.getItem(getPrefixedKey(SYNC_KEYS.FINANCES_SAVINGS_TARGETS));
 if (saved) {
 try {
 const parsed = JSON.parse(saved);
 // Migration: Ensure all goals have startDate and contributions
 const goalsWithHistory = parsed.map((g: any) => ({
 ...g,
 startDate: g.startDate || new Date().toISOString().split('T')[0],
 initialAmount: g.initialAmount || g.currentSaved || 0,
 contributions: g.contributions || []
 }));
 setGoals(goalsWithHistory);
 } catch (e) { console.error("Error parsing block:", e); }
 } else {
 // Initial mock data
 const mockGoals: SavingsGoal[] = [
 {
 id: '1',
 name: 'Dream Car',
 targetAmount: 45000,
 initialAmount: 5000,
 startDate: '2026-01-01',
 targetDate: '2029-12-01',
 contributions: [
 { id: 'c1', date: '2026-03-01', amount: 500 },
 { id: 'c2', date: '2026-03-15', amount: 250 },
 ]
 },
 {
 id: '2',
 name: 'House Fund',
 targetAmount: 250000,
 initialAmount: 25000,
 startDate: '2025-06-01',
 targetDate: '2030-06-01',
 contributions: [
 { id: 'h1', date: '2026-02-10', amount: 2000 },
 { id: 'h2', date: '2026-03-20', amount: 1500 },
 ]
 }
 ];
 setGoals(mockGoals);
 }
 setIsLoaded(true);

 const handleLocal = (e: any) => {
 if (e.detail && e.detail.key === SYNC_KEYS.FINANCES_SAVINGS_TARGETS) {
 const val = localStorage.getItem(getPrefixedKey(SYNC_KEYS.FINANCES_SAVINGS_TARGETS));
 if (val && val !== JSON.stringify(goalsRef.current)) {
 try { setGoals(JSON.parse(val)); } catch (e) { console.error("Error parsing block:", e); }
 }
 }
 };
 window.addEventListener('local-storage-change', handleLocal);
 return () => window.removeEventListener('local-storage-change', handleLocal);
 }, []);

 useEffect(() => {
 if (isLoaded) {
 setSyncedItem(SYNC_KEYS.FINANCES_SAVINGS_TARGETS, JSON.stringify(goals));
 }
 }, [goals, isLoaded]);


 const openAddModal = () => {
 setEditingGoal(null);
 setFormData({
 name: '',
 targetAmount: '',
 initialAmount: '0',
 startDate: new Date().toISOString().split('T')[0],
 targetDate: ''
 });
 setIsGoalModalOpen(true);
 };

 const openEditModal = (goal: SavingsGoal) => {
 setEditingGoal(goal);
 setFormData({
 name: goal.name,
 targetAmount: goal.targetAmount?.toString() || '',
 initialAmount: goal.initialAmount?.toString() || '',
 startDate: goal.startDate,
 targetDate: goal.targetDate
 });
 setIsGoalModalOpen(true);
 };

 const handleGoalSubmit = (e: React.FormEvent) => {
 e.preventDefault();
 const newGoal: SavingsGoal = {
 id: editingGoal ? editingGoal.id : Math.random().toString(36).substr(2, 9),
 name: formData.name,
 targetAmount: parseFloat(formData.targetAmount),
 initialAmount: parseFloat(formData.initialAmount),
 startDate: formData.startDate,
 targetDate: formData.targetDate,
 contributions: editingGoal ? editingGoal.contributions : []
 };

 if (editingGoal) {
 setGoals(goals.map(g => g.id === editingGoal.id ? newGoal : g));
 } else {
 setGoals([...goals, newGoal]);
 }
 setIsGoalModalOpen(false);
 };

 const recordContribution = (e: React.FormEvent) => {
 e.preventDefault();
 if (!targetGoalId || !contributionAmount) return;

 const newContrib: Contribution = {
 id: Math.random().toString(36).substr(2, 9),
 date: new Date().toISOString().split('T')[0],
 amount: parseFloat(contributionAmount)
 };

 setGoals(goals.map(g => 
 g.id === targetGoalId 
 ? { ...g, contributions: [newContrib, ...g.contributions] } 
 : g
 ));

 setIsContributionModalOpen(false);
 setContributionAmount('');
 setTargetGoalId(null);
 };

 const deleteContribution = (goalId: string, contribId: string) => {
 setGoals(goals.map(g => 
 g.id === goalId 
 ? { ...g, contributions: g.contributions.filter(c => c.id !== contribId) } 
 : g
 ));
 };

 const deleteGoal = (id: string) => {
 setGoals(goals.filter(g => g.id !== id));
 setIsGoalModalOpen(false);
 setEditingGoal(null);
 };

 const calculateTrajectoryMetrics = (goal: SavingsGoal) => {
 const totalContributed = (goal.contributions || []).reduce((sum, c) => sum + c.amount, 0);
 
 const currentTotal = goal.initialAmount + totalContributed;
 
 const progress = Math.min(100, (currentTotal / goal.targetAmount) * 100);
 const remaining = Math.max(0, goal.targetAmount - currentTotal);
 
 const now = new Date();
 const start = new Date(goal.startDate);
 const end = new Date(goal.targetDate);
 
 const totalDurationMonths = (end.getFullYear() - start.getFullYear()) * 12 + (end.getMonth() - start.getMonth());
 const monthsElapsed = (now.getFullYear() - start.getFullYear()) * 12 + (now.getMonth() - start.getMonth());
 const monthsRemaining = Math.max(1, totalDurationMonths - monthsElapsed);
 
 // Expected savings based on total goal (including initial amount) but distributed over time.
 const savingsToGain = goal.targetAmount - goal.initialAmount;
 const expectedCompoundedSavings = (savingsToGain / Math.max(1, totalDurationMonths)) * monthsElapsed;
 const expectedActual = goal.initialAmount + expectedCompoundedSavings;
 
 const status = currentTotal >= expectedActual ? 'Ahead' : 'Behind';
 const requiredMonthly = remaining / monthsRemaining;

 return { 
 progress, 
 currentTotal, 
 remaining, 
 requiredMonthly, 
 status, 
 monthsRemaining,
 recentContributions: (goal.contributions || []).slice(0, 3) 
 };
 };

 if (!isLoaded) return null;

 return (
 <div className="flex flex-col gap-6 md:gap-8 w-full transition-all duration-700 animate-in fade-in slide-in-from-bottom-8">
  <div className="flex flex-row items-center justify-between gap-4 px-1 md:px-2">
  <SectionTitle>
  Savings Planner
  </SectionTitle>
  <div className="flex items-center gap-3">
    <div className="flex bg-zinc-100 dark:bg-zinc-800 p-1 rounded-xl border border-zinc-200 dark:border-zinc-700">
      <button 
        onClick={() => toggleViewMode('grid')}
        className={`p-1.5 rounded-lg transition-all ${viewMode === 'grid' ? 'bg-white dark:bg-zinc-700 shadow-sm text-blue-600 dark:text-blue-400' : 'text-zinc-500 hover:text-zinc-700 dark:hover:text-zinc-300'}`}
        title="Grid View"
      >
        <LayoutGrid size={18} />
      </button>
      <button 
        onClick={() => toggleViewMode('table')}
        className={`p-1.5 rounded-lg transition-all ${viewMode === 'table' ? 'bg-white dark:bg-zinc-700 shadow-sm text-blue-600 dark:text-blue-400' : 'text-zinc-500 hover:text-zinc-700 dark:hover:text-zinc-300'}`}
        title="Table View"
      >
        <List size={18} />
      </button>
    </div>
    <button 
    onClick={openAddModal}
    className="bg-blue-600 text-white text-xs px-5 sm:px-8 py-2.5 sm:py-4 rounded-2xl hover:scale-105 active:scale-95 transition-all shadow-sm dark:shadow-none font-semibold"
    >
    New Goal
    </button>
  </div>
  </div>

  {viewMode === 'grid' ? (
    <div className="grid grid-cols-1 sm:grid-cols-2 md:grid-cols-2 xl:grid-cols-3 gap-6">
    {goals.map(goal => {
    const { progress, currentTotal, remaining, requiredMonthly, status, recentContributions } = calculateTrajectoryMetrics(goal);
    
    return (
    <div key={goal.id} className="bg-white dark:bg-zinc-900/60 border border-l-4 border-blue-100/50 dark:border-blue-900/30 rounded-2xl p-5 md:p-8 flex flex-col gap-5 md:gap-6 group shadow-sm transition-all relative overflow-hidden">
    {/* Header */}
    <div className="flex justify-between items-start gap-4">
    <div className="flex flex-col gap-1.5 flex-1">
    <div className="flex items-center gap-2">
    <h3 className="font-semibold text-xl md:text-2xl text-zinc-900 dark:text-zinc-100 capitalize">
    {goal.name}
    </h3>
    <div className={`hidden sm:block text-xs uppercase px-2.5 py-1 rounded-full border font-semibold ${ status === 'Ahead' ? "bg-emerald-50 text-emerald-600 border-emerald-100 dark:bg-emerald-500/10 dark:text-emerald-400 dark:border-emerald-900/30" : "bg-rose-50 text-rose-600 border-rose-100 dark:bg-rose-500/10 dark:text-rose-400 dark:border-rose-900/30" }`}>
    {status === 'Ahead' ? 'On Schedule' : 'Behind'}
    </div>
    </div>
    {/* Collapsed View Metric snippet for mobile */}
    <div className={`sm:hidden flex items-center justify-between ${expandedGoals[goal.id] ? 'hidden' : 'flex'}`}>
    <div className="flex items-baseline gap-1.5">
    <span className="text-blue-600 dark:text-blue-400 font-bold text-lg">{progress.toFixed(0)}%</span>
    <span className="text-xs text-zinc-500 dark:text-zinc-300 uppercase font-medium">${(currentTotal || 0).toLocaleString('en-CA', { maximumFractionDigits: 0 })}</span>
    </div>
    <span className={`text-[11px] uppercase font-semibold px-2 py-0.5 rounded-full ${status === 'Ahead' ? 'bg-emerald-500/10 text-emerald-600' : 'bg-rose-500/10 text-rose-600'}`}>
    {status}
    </span>
    </div>
    </div>
    <div className="flex items-center gap-1">
    <button onClick={() => openEditModal(goal)} className="p-2 text-zinc-400 hover:text-zinc-900 dark:hover:text-zinc-100 transition-colors">
    <svg className="w-5 h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M11 5H6a2 2 0 00-2 2v11a2 2 0 002 2h11a2 2 0 002-2v-5m-1.414-9.414a2 2 0 112.828 2.828L11.828 15H9v-2.828l8.586-8.586z" /></svg>
    </button>
    <button 
    onClick={() => toggleExpand(goal.id)}
    className="sm:hidden p-2 text-zinc-400 hover:text-zinc-900 transition-all"
    >
    <svg 
    className={`w-6 h-6 transition-transform duration-300 ${expandedGoals[goal.id] ? 'rotate-180' : ''}`} 
    fill="none" viewBox="0 0 24 24" stroke="currentColor"
    >
    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M19 9l-7 7-7-7" />
    </svg>
    </button>
    </div>
    </div>
   
    {/* Progress & Quick Add */}
    <div className={`flex flex-col gap-6 md:gap-10 sm:flex ${expandedGoals[goal.id] ? 'flex' : 'hidden'} animate-in slide-in-from-top-4 duration-300`}>
    <div className="flex flex-col gap-4 md:gap-6">
    <div className="flex flex-col gap-2 md:gap-3">
    <div className="flex justify-between items-end">
    <span className="text-2xl md:text-3xl text-zinc-900 dark:text-zinc-100 font-bold">
    {progress.toFixed(0)}<span className="text-lg text-zinc-500 dark:text-zinc-300 ml-1 font-medium">%</span>
    </span>
    <div className="flex flex-col items-end">
    <span className="text-xs md:text-xs text-zinc-500 dark:text-zinc-300 uppercase mb-0.5 text-right font-medium">
    ${(currentTotal || 0).toLocaleString('en-CA', { maximumFractionDigits: 0 })} / ${(goal.targetAmount || 0).toLocaleString('en-CA', { maximumFractionDigits: 0 })}
    </span>
    </div>
    </div>
    <div className="h-1.5 md:h-3 w-full bg-zinc-100 dark:bg-zinc-800 rounded-full overflow-hidden border border-zinc-200 dark:border-zinc-800/50">
    <div 
    className="h-full bg-blue-600 dark:bg-blue-500 rounded-full transition-all duration-1000 ease-out"
    style={{ width: `${progress}%` }}
    />
    </div>
    <span className="text-xs text-zinc-500 dark:text-zinc-400 uppercase font-medium mt-1">
    ${(remaining || 0).toLocaleString('en-CA', { maximumFractionDigits: 0 })} Remaining
    </span>
    </div>
   
    <div className="grid grid-cols-2 gap-3 md:gap-4">
    <div className="flex flex-col gap-0.5">
    <span className="text-[11px] md:text-xs text-zinc-600 dark:text-zinc-300 uppercase font-semibold">Start</span>
    <span className="text-xs md:text-sm text-zinc-900 dark:text-zinc-100 opacity-80 font-medium">
    {new Date(goal.startDate).toLocaleDateString('en-CA', { month: 'short', year: 'numeric' })}
    </span>
    </div>
    <div className="flex flex-col gap-0.5">
    <span className="text-[11px] md:text-xs text-zinc-600 dark:text-zinc-300 uppercase font-semibold">Target</span>
    <span className="text-xs md:text-sm text-zinc-900 dark:text-zinc-100 font-medium">
    {new Date(goal.targetDate).toLocaleDateString('en-CA', { month: 'short', year: 'numeric' })}
    </span>
    </div>
    <div className="flex flex-col gap-0.5 col-span-2">
    <span className="text-[11px] md:text-xs text-zinc-600 dark:text-zinc-300 uppercase leading-tight font-semibold">Required Contribution</span>
    <span className="text-sm md:text-base text-blue-500 font-bold">
    ${(Math.ceil(requiredMonthly) || 0).toLocaleString('en-CA', { maximumFractionDigits: 0 })}/mo
    </span>
    </div>
    </div>
   
    <button 
    onClick={() => {
    setTargetGoalId(goal.id);
    setIsContributionModalOpen(true);
    }}
    className="w-full bg-blue-600 text-white text-xs px-6 py-3.5 md:py-4 rounded-2xl hover:scale-[1.02] active:scale-95 transition-all shadow-sm dark:shadow-none flex items-center justify-center gap-2 font-semibold"
    >
    <svg className="w-4 h-4" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M12 6v6m0 0v6m0-6h6m-6 0H6" /></svg>
    Fuel Goal
    </button>
    </div>
   
    {/* Contribution History */}
    <div className="flex flex-col gap-4">
    <div className="flex items-center justify-between">
    <span className="text-xs text-zinc-600 dark:text-zinc-300 uppercase font-semibold">Activity</span>
    {(goal.contributions || []).length > 0 && (
    <button 
    onClick={() => {
    setHistoryGoalId(goal.id);
    setIsHistoryModalOpen(true);
    }}
    className="text-xs text-zinc-900 dark:text-zinc-100 uppercase hover:underline font-semibold"
    >
    View All
    </button>
    )}
    </div>
    
    <div className="flex flex-col gap-2">
    {(recentContributions || []).length > 0 ? recentContributions.map(c => (
    <div key={c.id} className="flex justify-between items-center p-3 bg-zinc-50 dark:bg-zinc-800/30 rounded-2xl border border-zinc-100 dark:border-zinc-800/50">
    <div className="flex flex-col">
    <span className="text-xs font-bold text-zinc-900 dark:text-zinc-100">
    ${(c.amount || 0).toLocaleString('en-CA', { maximumFractionDigits: 0 })}
    </span>
    <span className="text-xs text-zinc-500 dark:text-zinc-300">{new Date(c.date).toLocaleDateString('en-CA', { month: 'short', day: 'numeric' })}</span>
    </div>
    <div className="px-2 py-0.5 bg-zinc-100 dark:bg-zinc-800 rounded uppercase text-xs text-zinc-600 dark:text-zinc-400 font-semibold">Added</div>
    </div>
    )) : (
    <div className="flex flex-col items-center justify-center py-6 bg-zinc-50 dark:bg-zinc-800/10 rounded-3xl border border-dashed border-zinc-200 dark:border-zinc-800/50">
    <span className="text-xs text-zinc-500 dark:text-zinc-400 uppercase font-semibold">Empty</span>
    </div>
    )}
    </div>
    </div>
    </div>
    </div>
    );
    })}
    </div>
  ) : (
    <div className="bg-white dark:bg-zinc-950/30 border border-zinc-200 dark:border-zinc-800 rounded-2xl overflow-hidden shadow-sm animate-in fade-in duration-500">
      <div className="overflow-x-auto custom-scrollbar">
        <table className="w-full text-left border-collapse min-w-[800px]">
          <thead>
            <tr className="bg-zinc-50 dark:bg-zinc-950/50 border-b border-zinc-100 dark:border-zinc-800">
              <th className="p-4 px-6 text-[11px] uppercase text-zinc-500 font-bold tracking-wider">Goal Name</th>
              <th className="p-4 px-6 text-[11px] uppercase text-zinc-500 font-bold tracking-wider">Target</th>
              <th className="p-4 px-6 text-[11px] uppercase text-zinc-500 font-bold tracking-wider">Progress</th>
              <th className="p-4 px-6 text-[11px] uppercase text-zinc-500 font-bold tracking-wider">Status</th>
              <th className="p-4 px-6 text-[11px] uppercase text-zinc-500 font-bold tracking-wider">Monthly Req</th>
              <th className="p-4 px-6 text-[11px] uppercase text-zinc-500 font-bold tracking-wider text-right">Actions</th>
            </tr>
          </thead>
          <tbody className="divide-y divide-zinc-100 dark:divide-zinc-800/50">
            {goals.map(goal => {
              const { progress, currentTotal, remaining, requiredMonthly, status } = calculateTrajectoryMetrics(goal);
              return (
                <tr key={goal.id} className="hover:bg-zinc-50/50 dark:hover:bg-zinc-800/30 transition-colors group">
                  <td className="p-4 px-6">
                    <span className="font-semibold text-zinc-900 dark:text-zinc-100 capitalize">{goal.name}</span>
                  </td>
                  <td className="p-4 px-6">
                    <div className="flex flex-col">
                      <span className="text-sm font-bold text-zinc-900 dark:text-zinc-100">
                        ${(goal.targetAmount || 0).toLocaleString('en-CA', { maximumFractionDigits: 0 })}
                      </span>
                      <span className="text-[10px] text-zinc-500 uppercase font-medium">By {new Date(goal.targetDate).toLocaleDateString('en-CA', { month: 'short', year: 'numeric' })}</span>
                    </div>
                  </td>
                  <td className="p-4 px-6">
                    <div className="flex flex-col gap-2 min-w-[150px]">
                      <div className="flex justify-between items-center text-[10px] uppercase font-bold text-zinc-400">
                        <span>{progress.toFixed(0)}%</span>
                        <span>${(currentTotal || 0).toLocaleString('en-CA', { maximumFractionDigits: 0 })}</span>
                      </div>
                      <div className="w-full h-1.5 bg-zinc-100 dark:bg-zinc-800 rounded-full overflow-hidden">
                        <div 
                          className="h-full bg-blue-600 dark:bg-blue-500 rounded-full transition-all duration-1000"
                          style={{ width: `${progress}%` }}
                        />
                      </div>
                    </div>
                  </td>
                  <td className="p-4 px-6">
                    <span className={`inline-flex items-center px-2 py-0.5 rounded-md text-[10px] font-bold uppercase ${ status === 'Ahead' ? 'bg-emerald-50 text-emerald-600 dark:bg-emerald-500/10 dark:text-emerald-400' : 'bg-rose-50 text-rose-600 dark:bg-rose-500/10 dark:text-rose-400' }`}>
                      {status === 'Ahead' ? 'On Schedule' : 'Behind'}
                    </span>
                  </td>
                  <td className="p-4 px-6">
                    <span className="text-sm font-bold text-blue-500">
                      ${(Math.ceil(requiredMonthly) || 0).toLocaleString('en-CA', { maximumFractionDigits: 0 })}/mo
                    </span>
                  </td>
                  <td className="p-4 px-6 text-right">
                    <div className="flex items-center justify-end gap-1">
                      <button 
                        onClick={() => {
                          setTargetGoalId(goal.id);
                          setIsContributionModalOpen(true);
                        }}
                        className="p-2 text-zinc-400 hover:text-blue-600 dark:hover:text-blue-400 transition-colors"
                        title="Fuel Goal"
                      >
                        <svg className="w-4 h-4" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M12 6v6m0 0v6m0-6h6m-6 0H6" /></svg>
                      </button>
                      <button 
                        onClick={() => {
                          setHistoryGoalId(goal.id);
                          setIsHistoryModalOpen(true);
                        }}
                        className="p-2 text-zinc-400 hover:text-zinc-900 dark:hover:text-zinc-100 transition-colors"
                        title="View History"
                      >
                        <svg className="w-4 h-4" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M12 8v4l3 3m6-3a9 9 0 11-18 0 9 9 0 0118 0z" /></svg>
                      </button>
                      <button 
                        onClick={() => openEditModal(goal)}
                        className="p-2 text-zinc-400 hover:text-zinc-900 dark:hover:text-zinc-100 transition-colors"
                        title="Edit Goal"
                      >
                        <svg className="w-4 h-4" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M11 5H6a2 2 0 00-2 2v11a2 2 0 002 2h11a2 2 0 002-2v-5m-1.414-9.414a2 2 0 112.828 2.828L11.828 15H9v-2.828l8.586-8.586z" /></svg>
                      </button>
                    </div>
                  </td>
                </tr>
              );
            })}
          </tbody>
        </table>
      </div>
    </div>
  )}


 {/* Schema-Driven Add/Edit Goal Modal */}
 <Modal
 isOpen={isGoalModalOpen}
 onClose={() => setIsGoalModalOpen(false)}
 title={editingGoal ? 'Edit goal' : 'New target'}
 onSubmit={handleGoalSubmit}
 submitText={editingGoal ? 'Update' : 'Create'}
 accentColor="blue"
 >
 <DynamicForm
 sections={[
 {
 id: 'basic',
 title: 'Target details',
 fields: [
 { name: 'name', label: 'Goal Name', type: 'text', required: true, fullWidth: true, placeholder: 'e.g. Dream Car' },
 { name: 'targetAmount', label: 'Target Amount ($)', type: 'number', required: true, step: "0.01", placeholder: "0.00" },
 { name: 'initialAmount', label: 'Initial Balance', type: 'number', required: true, step: "0.01", placeholder: "0" },
 { name: 'startDate', label: 'Start Date', type: 'date', required: true },
 { name: 'targetDate', label: 'Target Date', type: 'date', required: true }
 ]
 }
 ]}
 formData={formData}
 accentColor="blue"
 onChange={(name, value) => setFormData(prev => ({ ...prev, [name]: value }))}
 />
 {editingGoal && (
 <div className="mt-4 flex justify-start w-full">
 <button 
 type="button" 
 onClick={() => deleteGoal(editingGoal.id)} 
 className="text-red-500 text-sm font-medium hover:text-red-600 transition-colors"
 >
 Delete Goal
 </button>
 </div>
 )}
 </Modal>

 {/* Schema-Driven Contribution Modal */}
 <Modal
 isOpen={isContributionModalOpen}
 onClose={() => setIsContributionModalOpen(false)}
 title="Fuel the target"
 onSubmit={recordContribution}
 submitText="Log Fuel"
 >
 <DynamicForm
 sections={[
 {
 id: 'fuel',
 title: 'Contribution',
 fields: [
 { name: 'amount', label: 'Amount', type: 'number', required: true, step: "0.01", placeholder: "0.00", fullWidth: true }
 ]
 }
 ]}
 formData={{ amount: contributionAmount }}
 onChange={(_, value) => setContributionAmount(value)}
 />
 </Modal>

 {/* Schema-Driven History Modal */}
 <Modal
 isOpen={isHistoryModalOpen && !!historyGoalId}
 onClose={() => setIsHistoryModalOpen(false)}
 title="Fuel history"
 onSubmit={(e) => { e.preventDefault(); setIsHistoryModalOpen(false); }}
 submitText="Done"
 >
 <div className="flex flex-col gap-4 max-h-[50vh] overflow-y-auto pr-2 custom-scrollbar">
 {(() => {
 const goal = goals.find(g => g.id === historyGoalId);
 if (!goal) return null;
 return (
 <div className="flex flex-col gap-3 w-full">
 {(goal.contributions || []).map(c => (
 <div key={c.id} className="flex justify-between items-center p-5 bg-zinc-50 dark:bg-zinc-800/30 rounded-3xl border border-zinc-100 dark:border-zinc-800/50 group">
 <div className="flex flex-col">
 <span className="text-lg font-bold text-zinc-900 dark:text-zinc-100">
 ${c.amount.toLocaleString('en-CA', { maximumFractionDigits: 0 })}
 </span>
 <span className="text-xs text-zinc-500 dark:text-zinc-300 uppercase font-medium">{new Date(c.date).toLocaleDateString('en-CA', { month: 'long', day: 'numeric', year: 'numeric' })}</span>
 </div>
 <button type="button" onClick={() => deleteContribution(historyGoalId as string, c.id)} className="p-2 text-zinc-400 hover:text-rose-500 opacity-0 group-hover:opacity-100 transition-all">
 <svg className="w-5 h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" /></svg>
 </button>
 </div>
 ))}
 {goal.initialAmount > 0 && (
 <div className="flex justify-between items-center p-5 bg-blue-50 dark:bg-blue-500/10 rounded-3xl border border-blue-100/50 dark:border-blue-900/30 mt-2">
 <div className="flex flex-col">
 <span className="text-lg font-bold text-blue-600 dark:text-blue-400">
 ${goal.initialAmount.toLocaleString('en-CA', { maximumFractionDigits: 0 })}
 </span>
 <span className="text-xs text-blue-500/50 uppercase font-bold">Starting Balance</span>
 </div>
 <div className="text-xs text-blue-500/40 uppercase px-3 py-1 bg-blue-50/50 dark:bg-blue-500/10 rounded-xl font-bold">Init</div>
 </div>
 )}
 </div>
 );
 })()}
 </div>
 </Modal>
 </div>
 );
}

