"use client";

import React, { useState, useEffect, useRef } from 'react';
import { getPrefixedKey } from '@/lib/keys';
import { SYNC_KEYS } from '@/lib/sync-keys';
import {
  MedicineItem,
  SupplementItem,
  MEDICINE_CATEGORIES,
  SUPPLEMENT_CATEGORIES,
  type InventoryStatus,
} from '@/types/health-system';
import {
  Activity,
  Clock,
  ShoppingCart,
  BarChart2,
  ChevronDown,
  ChevronUp,
  CheckCircle2,
} from 'lucide-react';

/* ─────────────────────────────────────────────
   Types
───────────────────────────────────────────── */
type StatusFilter = 'ALL' | 'LOW' | 'MISSING' | 'EXPIRED';
type InsightTab = 'expiry' | 'categories' | 'restock';

interface HealthInsightsPanelProps {
  activeFilter: StatusFilter;
  onFilterChange: (filter: StatusFilter) => void;
}

interface ExpiryItem {
  name: string;
  section: string;
  expiryDate: string;
  daysUntil: number;
  status: InventoryStatus;
}

interface RestockItemData {
  name: string;
  section: string;
  status: 'LOW' | 'MISSING';
  qty: number;
  target: number;
}

interface SectionStats {
  label: string;
  total: number;
  ok: number;
  low: number;
  missing: number;
  expired: number;
}

/* ─────────────────────────────────────────────
   Pure helpers (no hooks)
───────────────────────────────────────────── */
const getStatus = (item: {
  quantity: number;
  targetQuantity: number;
  expiryDate: string;
}): InventoryStatus => {
  const today = new Date();
  today.setHours(0, 0, 0, 0);
  const expiry = new Date(item.expiryDate);
  expiry.setHours(0, 0, 0, 0);
  if (expiry < today) return 'EXPIRED';
  if (item.quantity === 0) return 'MISSING';
  if (item.quantity < item.targetQuantity) return 'LOW';
  return 'OK';
};

const getDaysUntilExpiry = (expiryDate: string): number => {
  const today = new Date();
  today.setHours(0, 0, 0, 0);
  const expiry = new Date(expiryDate);
  expiry.setHours(0, 0, 0, 0);
  return Math.round((expiry.getTime() - today.getTime()) / (1000 * 60 * 60 * 24));
};

const getFrequencyGroup = (freq: string): string => {
  const f = freq.toLowerCase();
  if (f.includes('day') || f.includes('daily') || f.includes('/d')) return 'Daily';
  if (f.includes('week') || f.includes('weekly') || f.includes('/w')) return 'Weekly';
  if (f.includes('month') || f.includes('monthly')) return 'Monthly';
  return 'Other';
};

const FREQ_ORDER = ['Daily', 'Weekly', 'Monthly', 'Other'];



const statsFromItems = (items: Array<{ quantity: number; targetQuantity: number; expiryDate: string }>) => ({
  total: items.length,
  ok: items.filter(i => getStatus(i) === 'OK').length,
  low: items.filter(i => getStatus(i) === 'LOW').length,
  missing: items.filter(i => getStatus(i) === 'MISSING').length,
  expired: items.filter(i => getStatus(i) === 'EXPIRED').length,
});

const loadFromStorage = <T,>(key: string): T[] => {
  try {
    const raw = localStorage.getItem(getPrefixedKey(key));
    return raw ? JSON.parse(raw) : [];
  } catch {
    return [];
  }
};

/* ─────────────────────────────────────────────
   Restock Row — local checked state
───────────────────────────────────────────── */
function RestockRow({ item }: { item: RestockItemData }) {
