                      {s.low > 0 && (
                        <span className="text-xs font-bold text-amber-500">{s.low} low</span>
                      )}
                      {s.total > 0 && s.expired === 0 && s.missing === 0 && s.low === 0 && (
                        <span className="text-xs font-bold text-emerald-500">All good ✓</span>
                      )}
                    </div>
