"use client";

import React, { useState, useEffect, useMemo } from 'react';
import { ExpenseRecord, ExpenseItem, ExpenseCategory, Asset, PaymentMethod, EntryType } from '@/types/finance';
import { getPrefixedKey } from '@/lib/keys';
import { SYNC_KEYS } from '@/lib/sync-keys';
import { setSyncedItem } from '@/lib/storage';
import { calculateAssetBalance, updateAssetFromExpense, updateRecipientFromExpense } from '@/lib/finances';
import { Modal } from '../ui/Modal';
import { FormSection } from '../ui/FormSection';

interface PantryEntryModalProps {
 isOpen: boolean;
 date: string | null;
 recordsOnDate: ExpenseRecord[];
 onClose: () => void;
 onUpdateRecords: (records: ExpenseRecord[]) => void;
 allRecords: ExpenseRecord[];
 initialRecord?: ExpenseRecord | null;
 initialTab?: 'list' | 'form';
}

const CATEGORIES: ExpenseCategory[] = ['Grocery', 'Clothing', 'Transport', 'Dining', 'Bills', 'Other'];
const PAYMENT_METHODS: PaymentMethod[] = ['Cash', 'Debit Card', 'Credit Card', 'UPI / Wallet', 'Bank Transfer'];
const PAID_FROM_OPTIONS = ['Cash Wallet', 'Bank Account', 'Credit Card'];

export function PantryEntryModal({ isOpen, date, recordsOnDate, onClose, onUpdateRecords, allRecords, initialRecord, initialTab }: PantryEntryModalProps) {
 const [activeTab, setActiveTab] = useState<'list' | 'form'>(initialTab || (initialRecord ? 'form' : 'list'));
 const [editingRecord, setEditingRecord] = useState<ExpenseRecord | null>(initialRecord || null);
 
 // Date overriding within modal
 const [internalDate, setInternalDate] = useState(date || new Date().toISOString().split('T')[0]);
 
 const [vendor, setVendor] = useState(''); // Place of Shop
 const [paidFromId, setPaidFromId] = useState(''); // Asset ID
 const [notes, setNotes] = useState('');
 
 // Grocery Items (for Bills)
 const [items, setItems] = useState<ExpenseItem[]>([]);
 
 // Single Entry Fields (for Quick Entry or single-item categories)
 const [singleItem, setSingleItem] = useState({
 name: '',
 price: '',
 quantity: '',
 brand: '',
 notes: '',
 // clothing extras
 itemType: '',
 color: '',
 size: '',
 person: '',
 quality: '',
 // transport extras
 transportType: 'Ride' as ExpenseRecord['transportType'],
 // dining extras
 occasion: '',
 peopleCount: 1,
 // bills extras
 billType: ''
 });

 // Taxes
 const [sgst, setSgst] = useState('');
 const [cgst, setCgst] = useState('');

 const [assets, setAssets] = useState<Asset[]>([]);
 const [isAnalyzing, setIsAnalyzing] = useState(false);

 const handleScanReceipt = (e: React.ChangeEvent<HTMLInputElement>) => {
   if (e.target.files && e.target.files.length > 0) {
     setIsAnalyzing(true);
     // Mock AI analyzing delay
     setTimeout(() => {
       setIsAnalyzing(false);
       setVendor('Costco Wholesale');
       setItems([
         ...items,
         { id: Math.random().toString(36).substr(2, 9), name: 'Organic Milk 2%', category: 'Grocery', type: 'need', quantity: '1', unitPrice: 5.99, totalPrice: 5.99, brand: 'Kirkland', notes: 'Scanned receipt', size: '4L' },
         { id: Math.random().toString(36).substr(2, 9), name: 'Rotisserie Chicken', category: 'Dining', type: 'want', quantity: '1', unitPrice: 7.99, totalPrice: 7.99, brand: 'Kirkland', notes: 'Scanned receipt', size: '1.5kg' }
       ]);
     }, 2000);
   }
 };

 useEffect(() => {
 if (initialRecord) {
 startEdit(initialRecord);
 } else if (initialTab === 'form' || recordsOnDate.length === 0) {
 setActiveTab('form');
 resetForm();
 } else {
 setActiveTab('list');
 }
 
 const savedAssets = localStorage.getItem(getPrefixedKey(SYNC_KEYS.FINANCES_ASSETS));
 if (savedAssets) {
 try { setAssets(JSON.parse(savedAssets)); } catch (e) { console.error("Error parsing block:", e); }
 }
 }, [recordsOnDate, initialRecord]);

 const resetForm = () => {
 setEditingRecord(null);
 setVendor('');
 setPaidFromId('');
 setNotes('');
 setItems([]);
 setSgst('');
 setCgst('');
 setSingleItem({
 name: '',
 price: '',
 quantity: '',
 brand: '',
 notes: '',
 itemType: '',
 color: '',
 size: '',
 person: '',
 quality: '',
 transportType: 'Ride',
 occasion: '',
 peopleCount: 1,
 billType: ''
 });
 };

 // Load editing record
 const startEdit = (record: ExpenseRecord) => {
 setEditingRecord(record);
 setVendor(record.vendor || '');
 setPaidFromId(record.assetId || '');
 setNotes(record.notes || '');
 setSgst(record.sgst?.toString() || '');
 setCgst(record.cgst?.toString() || '');
 
 if (record.items) {
 setItems(record.items);
 } else {
 setItems([]);
 }

 setSingleItem({
 name: record.subcategory || '',
 price: record.amount.toString(),
 quantity: record.quantity || '',
 brand: record.brand || '',
 notes: record.notes || '',
 itemType: record.itemType || '',
 color: record.color || '',
 size: record.size || '',
 person: record.person || '',
 quality: record.quality || '',
 transportType: record.transportType || 'Ride',
 occasion: record.occasion || '',
 peopleCount: record.peopleCount || 1,
 billType: record.subcategory || ''
 });

 setActiveTab('form');
 };

 const handleAddItem = () => {
 setItems([...items, { id: Math.random().toString(36).substr(2, 9), name: '', category: 'Grocery', type: 'need', quantity: '', unitPrice: 0, totalPrice: 0, brand: '', notes: '', color: '', size: '', person: '', quality: '', itemType: '' }]);
 };

 const updateItem = (id: string, field: keyof ExpenseItem, value: any) => {
 setItems(items.map(item => {
 if (item.id === id) {
 const updated = { ...item, [field]: value };
 if (field === 'unitPrice' || field === 'quantity') {
 const q = parseFloat(updated.quantity) || 1;
 updated.totalPrice = updated.unitPrice * q; 
 }
 return updated;
 }
 return item;
 }));
 };

 const totalAmount = useMemo(() => {
 const itemsTotal = items.reduce((sum, i) => sum + i.totalPrice, 0);
 const taxTotal = (parseFloat(sgst) || 0) + (parseFloat(cgst) || 0);
 return itemsTotal + taxTotal;
 }, [items, sgst, cgst]);

 const handleSubmit = (e: React.FormEvent) => {
 e.preventDefault();
 if (!date) return;

 const newRecord: ExpenseRecord = {
 id: editingRecord ? editingRecord.id : Math.random().toString(36).substr(2, 9),
 entryType: 'Bill',
 category: (items[0]?.category as ExpenseCategory) || 'Grocery',
 vendor,
 paymentMethod: 'Debit Card',
 assetId: paidFromId || undefined,
 type: items[0]?.type || 'need',
 notes: notes,
 sgst: parseFloat(sgst) || undefined,
 cgst: parseFloat(cgst) || undefined,
 date: internalDate,
 amount: totalAmount,
 subcategory: vendor || items[0]?.name || 'Expense',
 paidToType: 'other',
 
 // Items for Bill mode
 items: items
 };

 // Cleanup for finance sync
 updateAssetFromExpense(newRecord.id, newRecord.assetId, newRecord.amount, newRecord.date, !!editingRecord);
 
 let updated;
 if (editingRecord) {
 updated = allRecords.map(r => r.id === editingRecord.id ? newRecord : r);
 } else {
 updated = [newRecord, ...allRecords];
 }
 
 onUpdateRecords(updated);
 onClose();
 };

 const deleteRecord = (id: string) => {
 const recordToDelete = allRecords.find(r => r.id === id);
 updateAssetFromExpense(id, undefined, 0, '', true);
 onUpdateRecords(allRecords.filter(r => r.id !== id));
 onClose();
 };

 if (!isOpen) return null;

 const modalTitle = (
 <div className="flex items-center gap-3">
 <input 
 type="date" 
 value={internalDate} 
 onChange={e => setInternalDate(e.target.value)}
 className="bg-transparent outline-none cursor-pointer appearance-none text-zinc-900 dark:text-white hover:text-teal-500 transition-colors w-32 font-semibold uppercase text-lg"
 />
 <span className="w-1.5 h-1.5 rounded-full bg-teal-500 hidden md:block" />
 <span className="text-zinc-400 font-semibold text-sm hidden md:block text-xs uppercase">{editingRecord ? 'Edit Entry' : 'New Entry'}</span>
 </div>
 );

 const headerControls = (
 <div className="flex bg-zinc-100/50 dark:bg-zinc-900/50 p-1 rounded-full border border-zinc-200/50 dark:border-zinc-800/50">
 <button type="button" onClick={() => setActiveTab('list')} className={`px-4 py-2 rounded-full text-xs uppercase font-semibold transition-all ${activeTab === 'list' ? 'bg-white dark:bg-zinc-800 shadow-sm text-zinc-900 dark:text-white' : 'text-zinc-400 hover:text-zinc-600 dark:hover:text-zinc-300'}`}>Records</button>
 <button type="button" onClick={() => setActiveTab('form')} className={`px-4 py-2 rounded-full text-xs uppercase font-semibold transition-all ${activeTab === 'form' ? 'bg-white dark:bg-zinc-800 shadow-md text-zinc-900 dark:text-white' : 'text-zinc-400 hover:text-zinc-600 dark:hover:text-zinc-300'}`}>Create</button>
 </div>
 );

 const footerControls = (
 <>
 <div className="flex flex-col">
 <span className="text-xs uppercase text-zinc-400 font-semibold mb-1">Total Bill Amount</span>
 <span className="text-3xl font-black text-teal-600 dark:text-teal-400 flex items-baseline gap-2 leading-none">
 ${totalAmount.toLocaleString('en-CA', { minimumFractionDigits: 2, maximumFractionDigits: 2 })}
 </span>
 </div>
 {editingRecord && activeTab === 'form' && (
 <button type="button" onClick={() => deleteRecord(editingRecord.id)} className="px-6 py-2 rounded-xl bg-rose-50 dark:bg-rose-500/10 hover:bg-rose-100 dark:hover:bg-rose-500/20 text-rose-600 dark:text-rose-400 transition-all text-xs uppercase font-semibold ml-4">Delete</button>
 )}
 </>
 );

 return (
 <Modal
 isOpen={isOpen}
 onClose={onClose}
 title={modalTitle}
 headerControls={headerControls}
 footerControls={activeTab === 'form' ? footerControls : undefined}
 maxWidth="max-w-3xl"
 onSubmit={activeTab === 'form' ? handleSubmit : undefined}
 submitText="Finalize Bill"
 cancelText={activeTab === 'list' ? 'Close' : 'Discard'}
 >
 <div className="flex-1">
 {activeTab === 'list' ? (
 <div className="space-y-6">
 {recordsOnDate.length === 0 ? (
 <div className="flex flex-col items-center py-32 opacity-30 gap-3">
 <svg className="w-16 h-16" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1} d="M19 11H5m14 0a2 2 0 012 2v6a2 2 0 01-2 2H5a2 2 0 01-2-2v-6a2 2 0 012-2m14 0V9a2 2 0 00-2-2M5 11V9a2 2 0 012-2m0 0V5a2 2 0 012-2h6a2 2 0 012 2v2M7 7h10" /></svg>
 <span className="text-sm uppercase">Empty calendar for this date</span>
 </div>
 ) : (
 recordsOnDate.map(record => (
 <div key={record.id} onClick={() => startEdit(record)} className="group p-3 rounded-xl bg-zinc-50/50 dark:bg-zinc-900/30 border border-zinc-100 dark:border-zinc-800 hover:border-zinc-200 dark:hover:border-zinc-700 transition-all cursor-pointer">
 <div className="flex justify-between items-center">
 <div className="flex items-center gap-3">
 <div className="w-12 h-12 rounded-lg bg-zinc-900 dark:bg-white flex items-center justify-center text-white dark:text-zinc-900 font-semibold uppercase text-sm">
 {record.category.charAt(0)}
 </div>
 <div className="flex flex-col gap-1">
 <div className="flex items-center gap-3">
 <span className="text-xl font-semibold text-zinc-900 dark:text-white">{record.vendor || record.subcategory}</span>
 <span className="px-2 py-0.5 rounded-lg bg-zinc-100 dark:bg-zinc-800 text-zinc-400 text-xs uppercase font-semibold">
 {record.entryType}
 </span>
 </div>
 <span className="text-sm uppercase text-zinc-400 font-semibold">{record.paymentMethod} • {assets.find(a => a.id === record.assetId)?.name || 'Direct'}</span>
 </div>
 </div>
 <div className="flex flex-col items-end gap-1">
 <span className="text-2xl font-bold text-zinc-900 dark:text-white flex items-baseline gap-1">
 ${record.amount.toLocaleString('en-CA', { minimumFractionDigits: 0, maximumFractionDigits: 0 })}
 </span>
 <span className={`text-xs uppercase font-semibold ${record.type === 'need' ? 'text-emerald-500' : 'text-amber-500'}`}>{record.type}</span>
 </div>
 </div>
 </div>
 ))
 )}
 </div>
 ) : (
 <div className="space-y-12 pb-12">
 
 <div className="flex justify-center mb-6">
 {/* Unified Bill Entry visual mode, toggle removed */}
 </div> {/* Section A: Basic Details */}
 <FormSection title="Basic Details" accentColor="teal">
 <div className="flex flex-col gap-2">
 <label className="text-xs uppercase font-semibold text-zinc-400 ml-2">Shop / Vendor Name</label>
 <input type="text" required value={vendor} onChange={e => setVendor(e.target.value)} placeholder="e.g. Walmart, Zara" className="bg-zinc-50 dark:bg-zinc-900 border-none px-4 py-3 rounded-2xl text-sm font-medium outline-none focus:ring-2 focus:ring-teal-500/30 transition-all w-full" />
 </div>
 <div className="flex flex-col gap-2">
 <label className="text-xs uppercase font-semibold text-zinc-400 ml-2">Paid From (Account)</label>
 <select value={paidFromId} onChange={e => setPaidFromId(e.target.value)} className="bg-zinc-50 dark:bg-zinc-900 border-none px-4 py-3 rounded-2xl text-sm font-medium outline-none focus:ring-2 focus:ring-teal-500/30 transition-all w-full appearance-none cursor-pointer">
 <option value="">Manual Entry (No Account)</option>
 {assets.map(a => <option key={a.id} value={a.id}>{a.name} (${calculateAssetBalance(a).toLocaleString('en-CA', { maximumFractionDigits: 0 })})</option>)}
 </select>
 </div>
 </FormSection>

 {/* Section B: Itemized Entries */}
 <div className="mt-8">
 <div className="flex items-center justify-between mb-4">
 <h3 className="text-sm font-semibold uppercase transition-colors text-teal-600 dark:text-teal-500">
 Itemized Content
 </h3>
 </div>

 <div className="space-y-6">
 <div className="grid gap-5">
 {isAnalyzing ? (
  <div className="py-24 bg-zinc-50/50 dark:bg-zinc-900/30 rounded-3xl border-2 border-dashed border-teal-200 dark:border-teal-800 flex flex-col items-center justify-center gap-4 transition-all">
   <div className="w-16 h-16 rounded-full bg-teal-50 dark:bg-teal-900/30 shadow-sm flex items-center justify-center text-teal-500 relative">
    <div className="absolute inset-0 border-4 border-t-teal-500 border-r-transparent border-b-teal-500/30 border-l-transparent rounded-full animate-spin" />
    <svg className="w-8 h-8" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M3 9a2 2 0 012-2h.93a2 2 0 001.664-.89l.812-1.22A2 2 0 0110.07 4h3.86a2 2 0 011.664.89l.812 1.22A2 2 0 0018.07 7H19a2 2 0 012 2v9a2 2 0 01-2 2H5a2 2 0 01-2-2V9z" /><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15 13a3 3 0 11-6 0 3 3 0 016 0z" /></svg>
   </div>
   <div className="flex flex-col items-center gap-1">
     <span className="text-sm uppercase font-bold text-teal-600 dark:text-teal-400">Analyzing Receipt</span>
     <span className="text-xs font-semibold text-teal-600/60 dark:text-teal-400/60">Extracting vendors and items using OCR...</span>
   </div>
  </div>
 ) : items.length === 0 ? (
 <div className="py-16 bg-zinc-50/50 dark:bg-zinc-900/30 rounded-3xl border-2 border-dashed border-zinc-200 dark:border-zinc-800 flex flex-col items-center justify-center gap-6 transition-all">
 <div className="w-20 h-20 rounded-full bg-white dark:bg-zinc-950 shadow-sm flex items-center justify-center text-zinc-400">
  <svg className="w-10 h-10" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1.5} d="M3 3h2l.4 2M7 13h10l4-8H5.4M7 13L5.4 5M7 13l-2.293 2.293c-.63.63-.184 1.707.707 1.707H17m0 0a2 2 0 100 4 2 2 0 000-4zm-8 2a2 2 0 11-4 0 2 2 0 014 0z" /></svg>
 </div>
 <div className="flex flex-col items-center gap-1 text-center px-4">
   <span className="text-sm uppercase font-bold text-zinc-600 dark:text-zinc-300">Bill Entry Mode</span>
   <span className="text-xs font-semibold text-zinc-500 max-w-sm">Capture a photo of your receipt to auto-fill items using AI, or enter them manually below.</span>
 </div>
 <div className="flex gap-4 items-center">
   <div className="relative overflow-hidden group">
     <button type="button" className="px-6 py-3 bg-teal-600 hover:bg-teal-700 text-white rounded-xl text-xs uppercase font-bold flex items-center gap-2 shadow-lg shadow-teal-500/20 transition-all active:scale-95">
       <svg className="w-4 h-4" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M3 9a2 2 0 012-2h.93a2 2 0 001.664-.89l.812-1.22A2 2 0 0110.07 4h3.86a2 2 0 011.664.89l.812 1.22A2 2 0 0018.07 7H19a2 2 0 012 2v9a2 2 0 01-2 2H5a2 2 0 01-2-2V9z" /><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15 13a3 3 0 11-6 0 3 3 0 016 0z" /></svg>
       Scan Receipt
     </button>
     <input type="file" accept="image/*" capture="environment" onChange={handleScanReceipt} className="absolute inset-0 opacity-0 cursor-pointer w-full h-full" title="Take Photo" />
   </div>
   <span className="text-[10px] font-bold text-zinc-400 uppercase">OR</span>
   <button type="button" onClick={handleAddItem} className="px-6 py-3 bg-zinc-900 dark:bg-white text-white dark:text-zinc-900 rounded-xl text-xs uppercase font-bold shadow-sm transition-all active:scale-95 hover:scale-105">
     Add Manually
   </button>
 </div>
 </div>
 ) : (
 items.map((item) => (
 <div key={item.id} className="flex flex-col gap-4 p-5 bg-zinc-50/50 dark:bg-zinc-900/30 rounded-2xl border border-zinc-100 dark:border-zinc-800 shadow-sm relative group animate-in slide-in-from-right-4 duration-300">
 <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
 <div className="flex flex-col gap-2">
 <label className="text-xs uppercase font-semibold text-zinc-400 ml-2">Item Name</label>
 <input type="text" placeholder="e.g. Milk 3%" value={item.name} onChange={e => updateItem(item.id, 'name', e.target.value)} className="bg-white dark:bg-zinc-950 border-none px-4 py-3 rounded-2xl text-sm font-medium outline-none focus:ring-2 focus:ring-teal-500/30 transition-all w-full shadow-sm" />
 </div>
 <div className="flex flex-col gap-2">
 <label className="text-xs uppercase font-semibold text-zinc-400 ml-2">Category</label>
 <select value={item.category} onChange={e => updateItem(item.id, 'category', e.target.value)} className="bg-white dark:bg-zinc-950 border-none px-4 py-3 rounded-2xl text-sm font-medium outline-none focus:ring-2 focus:ring-teal-500/30 transition-all w-full appearance-none cursor-pointer shadow-sm">
 {CATEGORIES.map(c => <option key={c} value={c}>{c}</option>)}
 <option value="Others">Others</option>
 </select>
 </div>

 {item.category === 'Others' && (
 <div className="flex flex-col gap-2 md:col-span-2">
 <label className="text-xs uppercase font-semibold text-zinc-400 ml-2">Custom Cat</label>
 <input type="text" placeholder="e.g. Hobby" value={item.quality} onChange={e => updateItem(item.id, 'quality', e.target.value)} className="bg-white dark:bg-zinc-950 border-none px-4 py-3 rounded-2xl text-sm font-medium outline-none focus:ring-2 focus:ring-teal-500/30 transition-all w-full shadow-sm" />
 </div>
 )}

 <div className="flex flex-col gap-2">
 <label className="text-xs uppercase font-semibold text-zinc-400 ml-2">Price</label>
 <input type="number" placeholder="0.00" value={item.unitPrice} onChange={e => updateItem(item.id, 'unitPrice', parseFloat(e.target.value))} className="bg-white dark:bg-zinc-950 border-none px-4 py-3 rounded-2xl text-sm font-semibold outline-none focus:ring-2 focus:ring-teal-500/30 transition-all w-full shadow-sm" />
 </div>
 <div className="flex flex-col gap-2">
 <label className="text-xs uppercase font-semibold text-zinc-400 ml-2">Qty</label>
 <input type="number" min="0" step="any" placeholder="1, 2..." value={item.quantity} onChange={e => updateItem(item.id, 'quantity', e.target.value)} className="bg-white dark:bg-zinc-950 border-none px-4 py-3 rounded-2xl text-sm font-medium outline-none focus:ring-2 focus:ring-teal-500/30 transition-all w-full shadow-sm" />
 </div>
 
 <div className="flex flex-col gap-2">
 <label className="text-xs uppercase font-semibold text-zinc-400 ml-2">Size/Wt</label>
 <input type="text" placeholder="3L, 2kg" value={item.size || ''} onChange={e => updateItem(item.id, 'size', e.target.value)} className="bg-white dark:bg-zinc-950 border-none px-4 py-3 rounded-2xl text-sm font-medium outline-none focus:ring-2 focus:ring-teal-500/30 transition-all w-full shadow-sm" />
 </div>
 <div className="flex flex-col gap-2">
 <label className="text-xs uppercase font-semibold text-zinc-400 ml-2">Brand</label>
 <input type="text" placeholder="Brand" value={item.brand} onChange={e => updateItem(item.id, 'brand', e.target.value)} className="bg-white dark:bg-zinc-950 border-none px-4 py-3 rounded-2xl text-sm font-medium outline-none focus:ring-2 focus:ring-teal-500/30 transition-all w-full shadow-sm" />
 </div>
 
 <div className="flex flex-col gap-2 md:col-span-2">
 <label className="text-xs uppercase font-semibold text-zinc-400 ml-2">Type</label>
 <div className="flex bg-zinc-100 dark:bg-zinc-900 rounded-2xl p-1 w-full shadow-sm">
 <button type="button" onClick={() => updateItem(item.id, 'type', 'need')} className={`flex-1 py-1.5 rounded-xl text-xs uppercase font-semibold transition-all ${item.type === 'need' ? 'bg-white dark:bg-zinc-800 shadow-sm text-zinc-900 dark:text-white' : 'text-zinc-400 hover:text-zinc-600 dark:hover:text-zinc-400'}`}>Need</button>
 <button type="button" onClick={() => updateItem(item.id, 'type', 'want')} className={`flex-1 py-1.5 rounded-xl text-xs uppercase font-semibold transition-all ${item.type === 'want' ? 'bg-white dark:bg-zinc-800 shadow-sm text-zinc-900 dark:text-white' : 'text-zinc-400 hover:text-zinc-600 dark:hover:text-zinc-400'}`}>Want</button>
 </div>
 </div>
 
 <div className="flex flex-col gap-2 md:col-span-2">
 <label className="text-xs uppercase font-semibold text-zinc-400 ml-2">Notes & Details</label>
 <input type="text" placeholder="Any additional notes..." value={item.notes || ''} onChange={e => updateItem(item.id, 'notes', e.target.value)} className="bg-white dark:bg-zinc-950 border-none px-4 py-3 rounded-2xl text-sm font-medium outline-none focus:ring-2 focus:ring-teal-500/30 transition-all w-full shadow-sm" />
 </div>
 </div>
 <button type="button" title="Delete Item" onClick={() => setItems(items.filter(i => i.id !== item.id))} className="absolute -top-3 -right-3 bg-zinc-900 dark:bg-zinc-100 hover:bg-rose-500 dark:hover:bg-rose-500 text-white dark:text-zinc-900 hover:text-white transition-all w-8 h-8 rounded-full flex items-center justify-center shadow-lg shadow-zinc-200 dark:shadow-none opacity-0 group-hover:opacity-100">×</button>
 </div>
 ))
 )}
 </div>

 {items.length > 0 && !isAnalyzing && (
 <div className="flex flex-col sm:flex-row justify-center items-center gap-4 pt-4">
 <div className="relative overflow-hidden group">
   <button type="button" className="px-6 py-3 bg-teal-50 dark:bg-teal-900/20 text-teal-600 dark:text-teal-400 border border-teal-200 dark:border-teal-800 rounded-full text-xs uppercase font-bold flex items-center gap-2 transition-all active:scale-95 shadow-sm">
     <svg className="w-4 h-4" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M3 9a2 2 0 012-2h.93a2 2 0 001.664-.89l.812-1.22A2 2 0 0110.07 4h3.86a2 2 0 011.664.89l.812 1.22A2 2 0 0018.07 7H19a2 2 0 012 2v9a2 2 0 01-2 2H5a2 2 0 01-2-2V9z" /></svg>
     Scan Receipt
   </button>
   <input type="file" accept="image/*" capture="environment" onChange={handleScanReceipt} className="absolute inset-0 opacity-0 cursor-pointer w-full h-full" title="Take another photo" />
 </div>
 <button type="button" onClick={handleAddItem} className="px-8 py-4 bg-zinc-900 dark:bg-white text-white dark:text-zinc-950 rounded-full text-sm uppercase font-semibold hover:scale-105 active:scale-95 transition-all shadow-xl shadow-zinc-200 dark:shadow-none inline-flex items-center gap-2">
 <span>Add Another Item</span>
 <svg className="w-5 h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M12 4v16m8-8H4"/></svg>
 </button>
 </div>
 )}
 </div>
 </div>

 {/* Section C: Tax Section */}
 <div className="mt-8">
 <FormSection title="Tax Apportionment (Optional)" accentColor="teal" isAdvanced>
 <div className="flex flex-col gap-2">
 <label className="text-xs uppercase font-semibold text-zinc-400 ml-2">SGST / State Tax</label>
 <input type="number" step="0.01" value={sgst} onChange={e => setSgst(e.target.value)} placeholder="0.00" className="bg-zinc-50 dark:bg-zinc-900 border-none px-4 py-3 rounded-2xl text-sm font-medium outline-none focus:ring-2 focus:ring-teal-500/30 transition-all w-full" />
 </div>
 <div className="flex flex-col gap-2">
 <label className="text-xs uppercase font-semibold text-zinc-400 ml-2">CGST / Central Tax</label>
 <input type="number" step="0.01" value={cgst} onChange={e => setCgst(e.target.value)} placeholder="0.00" className="bg-zinc-50 dark:bg-zinc-900 border-none px-4 py-3 rounded-2xl text-sm font-medium outline-none focus:ring-2 focus:ring-teal-500/30 transition-all w-full" />
 </div>
 </FormSection>
 </div>

 </div>
 )}
 </div>
 </Modal>
 );
}

"use client";

import React from 'react';
import { Text } from '@/components/ui/Text';

interface PantryFilterProps {
  viewingDate: Date;
  onDateChange: (date: Date) => void;
  onAddClick: () => void;
}

export function PantryFilter({ viewingDate, onDateChange, onAddClick }: PantryFilterProps) {
  const month = viewingDate.getMonth();
  const year = viewingDate.getFullYear();

  const prevMonth = () => onDateChange(new Date(year, month - 1, 1));
  const nextMonth = () => onDateChange(new Date(year, month + 1, 1));

  const monthName = new Intl.DateTimeFormat('en-US', { month: 'long' }).format(viewingDate);

  // We could add dropdowns here, but for now we'll keep them as semantic buttons
