  <p className="text-zinc-500 font-medium">{itemStats.length === 0 ? "No grocery items logged yet. Add items in Quick Entry or detailed bills." : "No items found matching your search."}</p>
  </div>
   ) : viewMode === 'grid' ? (
  <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-4 max-h-[500px] overflow-y-auto pr-2 custom-scrollbar">

 {filteredStats.map(stat => (
 <div key={stat.name} onClick={() => setActiveItemStats(stat)} className="group bg-white dark:bg-zinc-900 border border-zinc-200 dark:border-zinc-800 rounded-2xl p-6 shadow-sm transition-all duration-300 hover:-translate-y-1 flex flex-col justify-between cursor-pointer">

 <div>
 {/* Name & Trend Indicator */}
 <div className="flex justify-between items-start mb-4">
 <div className="flex flex-col gap-1 max-w-[70%]">
 <h4 className="font-semibold text-[17px] text-zinc-900 dark:text-zinc-100 truncate" title={stat.name}>{stat.name}</h4>
 <span className="text-[11px] uppercase font-semibold text-zinc-500 dark:text-zinc-400">{stat.history.length} Logs</span>
 </div>
 <div className={`px-2 py-1 rounded-lg text-xs font-semibold whitespace-nowrap ${ stat.priceTrend > 3 ? 'bg-rose-50 dark:bg-rose-500/10 text-rose-600 dark:text-rose-400' : stat.priceTrend < -3 ? 'bg-teal-50 dark:bg-teal-500/10 text-teal-600 dark:text-teal-400' : 'bg-zinc-100 dark:bg-zinc-800 text-zinc-500 dark:text-zinc-400' }`}>
 {stat.priceTrend > 0 ? '↑' : stat.priceTrend < 0 ? '↓' : ''} {Math.abs(stat.priceTrend).toFixed(1)}% vs avg
 </div>
 </div>

 {/* Price & Sparkline */}
 <div className="flex items-end justify-between mb-5">
 <div className="flex flex-col gap-0.5">
 <span className="text-4xl font-bold text-zinc-900 dark:text-white leading-none">
