 at {stat.lastPurchase.vendor} {stat.lastPurchase.brand ? `(${stat.lastPurchase.brand})` : ''}
 </span>
 </div>
 {renderSparkline(stat.history, stat.priceTrend)}
 </div>

 {/* Avg vs Lowest Tracker */}
 <div className="flex justify-between text-sm mb-4 p-4 bg-zinc-50 dark:bg-zinc-950/40 rounded-2xl border border-zinc-100 dark:border-zinc-800/50">
 <div className="flex flex-col gap-1.5">
 <span className="text-[11px] text-zinc-600 dark:text-zinc-300 font-semibold uppercase">Average</span>
 <span className="font-semibold text-zinc-800 dark:text-zinc-200 text-sm">
 ${stat.averagePrice.toLocaleString("en-CA", {maximumFractionDigits:2})}
 </span>
 </div>
 <div className="w-px h-8 bg-zinc-200 dark:bg-zinc-800 my-auto" />
 <div className="flex flex-col gap-1.5 text-right">
 <span className="text-[11px] text-zinc-600 dark:text-zinc-300 font-semibold uppercase">Lowest</span>
 <span className="font-bold text-teal-600 dark:text-teal-400 text-sm">
 ${stat.lowestPrice.price.toLocaleString("en-CA", {maximumFractionDigits:2})}
 </span>
 </div>
 </div>
 </div>

 {/* Insights Footer */}
 {stat.smartInsights.length > 0 && (
 <div className="flex flex-wrap gap-1.5 mt-auto pt-2">
 {stat.smartInsights.slice(0, 2).map((insight, idx) => ( // max 2 insights for space
 <span key={idx} className={`text-xs font-semibold uppercase px-2 py-1 rounded-[8px] truncate max-w-full ${ insight.type === 'positive' ? 'bg-teal-50 dark:bg-teal-500/10 text-teal-600 dark:text-teal-400 border border-teal-100 dark:border-teal-500/20' : insight.type === 'negative' ? 'bg-rose-50 dark:bg-rose-500/10 text-rose-600 dark:text-rose-400 border border-rose-100 dark:border-rose-500/20' : 'bg-zinc-100 dark:bg-zinc-800 text-zinc-600 dark:text-zinc-300 border border-zinc-200 dark:border-zinc-700' }`} title={insight.text}>
 {insight.text}
 </span>
 ))}
 {stat.smartInsights.length > 2 && (
 <span className="text-xs font-semibold uppercase px-2 py-1 rounded-[8px] bg-zinc-100 dark:bg-zinc-800 text-zinc-500 border border-zinc-200 dark:border-zinc-700">
 +{stat.smartInsights.length - 2}
 </span>
 )}
 </div>
 )}
  </div>
  ))}
  </div>
  ) : (
    renderTableView()
  )}


 {/* Pop-up Modal for Detailed Tracking */}
 {activeItemStats && (
 <Modal
 isOpen={!!activeItemStats}
 onClose={() => setActiveItemStats(null)}
 title={activeItemStats.name}
 cancelText="Close"
