 <div key={idx} className={`p-4 rounded-2xl border flex items-center gap-3 text-sm font-semibold ${ insight.type === 'positive' ? 'bg-teal-50 dark:bg-teal-500/10 text-teal-700 dark:text-teal-300 border-teal-100 dark:border-teal-500/20' : insight.type === 'negative' ? 'bg-rose-50 dark:bg-rose-500/10 text-rose-700 dark:text-rose-300 border-rose-100 dark:border-rose-500/20' : 'bg-zinc-50 dark:bg-zinc-800/50 text-zinc-700 dark:text-zinc-300 border-zinc-200 dark:border-zinc-700' }`}>
 <span className="flex-shrink-0 mt-px">
 {insight.type === 'positive' ? <Sparkles size={20} className="text-teal-500" /> : 
 insight.type === 'negative' ? <AlertTriangle size={20} className="text-rose-500" /> : 
 <Lightbulb size={20} className="text-amber-500" />}
 </span>
 {insight.text}
 </div>
 ))}
