"use client";

import React from 'react';
import { ExpenseRecord } from '@/types/finance';
import { SectionTitle } from '../ui/Text';

interface SmartInsightsProps {
 records: ExpenseRecord[];
 viewingDate: Date;
}

interface InsightItem {
 text: string;
 trend?: string;
}

interface InsightSection {
 category: string;
 icon: React.ReactNode;
 color: string;
 bgColor: string;
 borderColor: string;
 items: InsightItem[];
}

export function SmartInsights({ records, viewingDate }: SmartInsightsProps) {
 const insights = React.useMemo(() => {
 const now = viewingDate;
 const currentMonth = now.getMonth();
 const lastMonth = currentMonth === 0 ? 11 : currentMonth - 1;
 const currentYear = now.getFullYear();
 const lastMonthYear = currentMonth === 0 ? currentYear - 1 : currentYear;

 const startOfThisWeek = new Date(now);
 startOfThisWeek.setDate(now.getDate() - now.getDay());
 startOfThisWeek.setHours(0, 0, 0, 0);

 // 1. Grocery Insights logic
 const groceryRecords = records.filter(r => r.category === 'Grocery');
 const thisMonthGrocery = groceryRecords.filter(r => {
 if (!r.date) return false;
 const [rYear, rMonth] = r.date.split('-');
 return parseInt(rMonth) - 1 === currentMonth && parseInt(rYear) === currentYear;
 }).reduce((acc, r) => acc + r.amount, 0);

 const lastMonthGrocery = groceryRecords.filter(r => {
 if (!r.date) return false;
 const [rYear, rMonth] = r.date.split('-');
 return parseInt(rMonth) - 1 === lastMonth && parseInt(rYear) === lastMonthYear;
 }).reduce((acc, r) => acc + r.amount, 0);

 const groceryDiff = lastMonthGrocery > 0 ? ((thisMonthGrocery - lastMonthGrocery) / lastMonthGrocery) * 100 : 0;
 
  // Dynamic Top Item Tracking
  const itemStats: Record<string, { count: number, prices: {date: string, price: number}[] }> = {};
  records.forEach(r => {
    r.items?.forEach(i => {
      const name = i.name.toLowerCase().trim();
      if (!name) return;
      if (!itemStats[name]) itemStats[name] = { count: 0, prices: [] };
      itemStats[name].count += 1;
      itemStats[name].prices.push({ date: r.date, price: i.unitPrice });
    });
  });

  const topItems = Object.entries(itemStats)
    .sort((a, b) => b[1].count - a[1].count)
    .slice(0, 3)
    .map(([name, stats]) => {
       stats.prices.sort((a, b) => new Date(a.date).getTime() - new Date(b.date).getTime());
       let isRising = false;
       let isFalling = false;
       if (stats.prices.length >= 2) {
         const first = stats.prices[0].price;
         const last = stats.prices[stats.prices.length - 1].price;
         isRising = last > first;
         isFalling = last < first;
       }
       
       const dates = stats.prices.map(p => new Date(p.date).getTime());
       let avgGap = 0;
       if (dates.length >= 2) {
         let gapSum = 0;
         for (let i = 1; i < dates.length; i++) {
           gapSum += (dates[i] - dates[i-1]) / (1000 * 60 * 60 * 24);
         }
         avgGap = gapSum / (dates.length - 1);
       }
       return { name, isRising, isFalling, avgGap, count: stats.count };
    });

 // 2. Spending Behavior logic
 const diningRecords = records.filter(r => r.category === 'Dining');
 const thisWeekDining = diningRecords.filter(r => new Date(r.date) >= startOfThisWeek).reduce((acc, r) => acc + r.amount, 0);
 const avgWeeklyDining = diningRecords.length > 0 ? (diningRecords.reduce((acc, r) => acc + r.amount, 0) / (records.length / 7 || 1)) : 0;

 const clothingRecords = records.filter(r => r.category === 'Clothing');
 const thisMonthClothing = clothingRecords.filter(r => {
 if (!r.date) return false;
 const [rYear, rMonth] = r.date.split('-');
 return parseInt(rMonth) - 1 === currentMonth && parseInt(rYear) === currentYear;
 }).reduce((acc, r) => acc + r.amount, 0);

 // 3. Habit Insights logic
 const impulseCount = records.filter(r => r.type === 'want' && new Date(r.date) >= startOfThisWeek).length;

 // 4. Optimization Insights logic
 const vendorPrices: Record<string, {vendor: string, price: number, date: string}[]> = {};
 records.forEach(r => {
 if (!r.vendor) return;
 r.items?.forEach(i => {
 const name = i.name.toLowerCase();
 if (!vendorPrices[name]) vendorPrices[name] = [];
 vendorPrices[name].push({ vendor: r.vendor || 'Unknown', price: i.unitPrice, date: r.date });
 });
 });

 let bestVendor = "";
 let potentialSavings = 0;
 
 // Find biggest price gap for the same item between vendors
 for (const [itemName, prices] of Object.entries(vendorPrices)) {
 if (prices.length >= 2) {
 const sorted = [...prices].sort((a, b) => a.price - b.price);
 const cheapest = sorted[0];
 const mostExpensive = sorted[sorted.length - 1];
 if (cheapest.vendor !== mostExpensive.vendor && mostExpensive.price > cheapest.price) {
 const diff = mostExpensive.price - cheapest.price;
 if (diff > potentialSavings) {
 potentialSavings = diff;
 bestVendor = cheapest.vendor;
 }
 }
 }
 }

 // Build the dynamic insight sections
 const sections: InsightSection[] = [];
 
 // Grocery insights
 const groceryItems: InsightItem[] = [];
 if (lastMonthGrocery > 0 && Math.abs(groceryDiff) >= 5) {
 groceryItems.push({ 
 text: groceryDiff > 0 
 ? `“You spent ${Math.abs(Math.round(groceryDiff))}% more on groceries this month vs last month”` 
 : `“You saved ${Math.abs(Math.round(groceryDiff))}% on groceries vs last month”`, 
 trend: groceryDiff > 0 ? "up" : "down" 
 });
 }

  topItems.forEach(item => {
    if (item.isRising) {
      groceryItems.push({ text: `“Price rising for ${item.name} observed in recent bills”`, trend: "warning" });
    } else if (item.isFalling) {
      groceryItems.push({ text: `“Price dropped for ${item.name} in recent bills”`, trend: "down" });
    }
  });
 
 if (groceryItems.length > 0) {
 sections.push({
 category: "Grocery Insights",
 icon: <svg className="w-5 h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M3 3h2l.4 2M7 13h10l4-8H5.4M7 13L5.4 5M7 13l-2.293 2.293c-.63.63-.184 1.707.707 1.707H17m0 0a2 2 0 100 4 2 2 0 000-4zm-8 2a2 2 0 11-4 0 2 2 0 014 0z" /></svg>,
 color: "text-emerald-500", bgColor: "bg-emerald-50 dark:bg-emerald-500/10", borderColor: "border-emerald-100 dark:border-emerald-500/20",
 items: groceryItems
 });
 }

 // Spending Behavior
 const behaviorItems: InsightItem[] = [];
 if (thisWeekDining > avgWeeklyDining * 1.3 && avgWeeklyDining > 0) {
 behaviorItems.push({ text: "“You spent significantly more on eating out this week than your average”" });
 }
 if (thisMonthClothing > 0) {
 behaviorItems.push({ text: `“Clothing spend tracked at $${thisMonthClothing.toFixed(0)} this month”` });
 }
 
 if (behaviorItems.length > 0) {
 sections.push({
 category: "Spending Behavior",
 icon: <svg className="w-5 h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 19v-6a2 2 0 00-2-2H5a2 2 0 00-2 2v6a2 2 0 002 2h2a2 2 0 002-2m0 0V9a2 2 0 012-2h2a2 2 0 012 2v10m-6 0a2 2 0 002 2h2a2 2 0 002-2m0 0V5a2 2 0 012-2h2a2 2 0 012 2v14a2 2 0 01-2 2h-2a2 2 0 01-2-2z" /></svg>,
 color: "text-blue-500", bgColor: "bg-blue-50 dark:bg-blue-500/10", borderColor: "border-blue-100 dark:border-blue-500/20",
 items: behaviorItems
 });
 }

 // Habit Insights
 const habitItems: InsightItem[] = [];
  
  topItems.forEach(item => {
    if (item.avgGap > 0 && item.count >= 2) {
      habitItems.push({ text: `“You buy ${item.name} every ${Math.round(item.avgGap)} days (consistent run rate)”` });
    }
  });

  if (impulseCount > 2) {
  habitItems.push({ text: `“${impulseCount} impulse purchases identified this week”` });
  }
 
 if (habitItems.length > 0) {
 sections.push({
 category: "Habit Insights",
 icon: <svg className="w-5 h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 8v4l3 3m6-3a9 9 0 11-18 0 9 9 0 0118 0z" /></svg>,
 color: "text-purple-500", bgColor: "bg-purple-50 dark:bg-purple-500/10", borderColor: "border-purple-100 dark:border-purple-500/20",
 items: habitItems
 });
 }

 // Optimization Insights
 const optItems: InsightItem[] = [];
 if (potentialSavings > 0 && bestVendor) {
 optItems.push({ text: `“Buying from ${bestVendor} could save ~$${potentialSavings.toFixed(1)} based on recent comparisons”` });
 }
 
 if (optItems.length > 0) {
 sections.push({
 category: "Optimization Insights",
 icon: <svg className="w-5 h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M13 10V3L4 14h7v7l9-11h-7z" /></svg>,
 color: "text-amber-500", bgColor: "bg-amber-50 dark:bg-amber-500/10", borderColor: "border-amber-100 dark:border-amber-500/20",
 items: optItems
 });
 }

 return sections;
 }, [records, viewingDate]) as InsightSection[];

 if (!insights || insights.length === 0) {
 return null;
 }

 return (
 <div className="flex flex-col gap-6 animate-in fade-in duration-700 delay-500">
 <div className="flex flex-col gap-3">
 <div className="flex items-center gap-3">
 <div className="w-10 h-10 rounded-2xl bg-zinc-900 dark:bg-white flex items-center justify-center text-white dark:text-zinc-900 shadow-lg">
 <svg className="w-6 h-6" fill="none" viewBox="0 0 24 24" stroke="currentColor">
 <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9.663 17h4.674a1 1 0 00.922-.606l.333-.833H8.408l.333.833a1 1 0 00.922.606zM10 5V3.5a1.5 1.5 0 10-3 0V5a5 5 0 0110 0v1.5a1.5 1.5 0 10-3 0V5a2 2 0 11-4 0z" />
 <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 11V15M12 7H12.01" />
 </svg>
 </div>
 <div className="flex flex-col">
 <SectionTitle>Smart Insights</SectionTitle>
 <p className="text-xs text-zinc-500 uppercase font-semibold">AI-Powered Optimization & Personal Spending Intelligence</p>
 </div>
 </div>
 </div>

 <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
 {insights.map((section, idx) => (
 <div 
 key={idx} 
 className={`group relative p-6 bg-white dark:bg-zinc-900 border ${section.borderColor} rounded-2xl shadow-sm transition-all duration-300 flex flex-col gap-5`}
 >
 {/* Header */}
 <div className="flex items-center gap-3">
 <div className={`p-2.5 rounded-xl ${section.bgColor} ${section.color}`}>
 {section.icon}
 </div>
 <h3 className="font-semibold text-sm uppercase text-zinc-800 dark:text-zinc-200">
 {section.category}
 </h3>
 </div>

 {/* Content Items */}
 <div className="flex flex-col gap-4">
 {section.items.map((item, iIdx) => (
 <div key={iIdx} className="flex items-start gap-3 group/item">
 <span className="mt-1 text-xs shrink-0 select-none text-zinc-500 group-hover/item:text-zinc-700 dark:group-hover/item:text-zinc-300 transition-colors">
 •
 </span>
 <p className="text-sm font-medium text-zinc-600 dark:text-zinc-300 leading-relaxed group-hover/item:text-zinc-900 dark:group-hover/item:text-zinc-100 transition-colors">
 {item.text}
 </p>
 </div>
 ))}
 </div>

 {/* Subtle Gradient Decor */}
 <div className={`absolute bottom-0 right-0 w-24 h-24 rounded-full blur-3xl opacity-0 group-hover:opacity-20 transition-opacity pointer-events-none ${section.bgColor}`} />
 </div>
 ))}
 </div>

 {/* Action Footer */}
 <div className="flex flex-col md:flex-row items-center justify-between p-6 bg-zinc-50 dark:bg-zinc-950/30 rounded-2xl border border-dashed border-zinc-200 dark:border-zinc-800 gap-4 mt-2">
 <div className="flex items-center gap-3">
 <div className="w-2 h-2 rounded-full bg-emerald-500 animate-pulse" />
 <p className="text-xs font-semibold text-zinc-500 uppercase">Insights are calculated daily based on your transaction history.</p>
 </div>
 <button className="px-5 py-2 text-xs font-semibold uppercase text-zinc-600 dark:text-zinc-400 bg-white dark:bg-zinc-900 border border-zinc-200 dark:border-zinc-800 rounded-xl hover:bg-zinc-900 hover:text-white dark:hover:bg-white dark:hover:text-zinc-900 transition-all shadow-sm">
 Recalculate Now
 </button>
 </div>
 </div>
 );
}

import React, { useCallback } from 'react';
import { FormSection, AccentColor } from './FormSection';
import { FormField, FormFieldProps } from './FormField';

export interface FormSchemaField extends Omit<FormFieldProps, 'value' | 'onChange'> {
 // Add any schema specific additions here if needed
}

export interface FormSchemaSection {
 id: string;
 title: string;
 fields: FormSchemaField[];
 isAdvanced?: boolean;
 initiallyExpanded?: boolean;
}

interface DynamicFormProps {
 id?: string;
 sections: FormSchemaSection[];
 formData: Record<string, any>;
 onChange: (name: string, value: any) => void;
 onSubmit?: (e: React.FormEvent) => void;
 errors?: Record<string, string>;
 isReadonly?: boolean;
 accentColor?: AccentColor;
}

export const DynamicForm: React.FC<DynamicFormProps> = ({
 id = 'dynamic-form',
 sections,
 formData,
 onChange,
 onSubmit,
 errors = {},
 isReadonly = false,
 accentColor = 'blue',
}) => {
 const handleChange = useCallback((name: string, value: any) => {
 onChange(name, value);
 }, [onChange]);

 return (
 <div id={id} className="space-y-8">
 {sections.map((section) => {
 // Skip empty sections
 if (!section.fields || section.fields.length === 0) return null;
 
 return (
 <FormSection
 key={section.id}
 title={section.title}
 isAdvanced={section.isAdvanced}
 initiallyExpanded={section.initiallyExpanded}
 accentColor={accentColor}
 >
 {section.fields.map((field) => (
 <FormField
 key={field.name}
 {...field}
 value={formData[field.name]}
 onChange={handleChange}
 error={errors[field.name]}
 disabled={isReadonly || field.disabled}
 />
 ))}
 </FormSection>
 );
 })}
 </div>
 );
};

import React, { memo } from 'react';
import { Text } from './Text';
import { cn } from '@/lib/utils';

export type FieldType = 'text' | 'select' | 'date' | 'number' | 'textarea' | 'rating';

export interface FormFieldProps {
 name: string;
 label: string;
 type?: FieldType;
 value: any;
 onChange: (name: string, value: any) => void;
 options?: string[] | { label: string; value: string }[];
 fullWidth?: boolean;
 required?: boolean;
 placeholder?: string;
 error?: string;
 disabled?: boolean;
 min?: number;
 max?: number;
 step?: number | string;
 // Custom render for overrides
 render?: (props: FormFieldProps) => React.ReactNode;
}

const FormFieldComponent: React.FC<FormFieldProps> = (props) => {
 const {
 name,
 label,
 type = 'text',
 value,
 onChange,
 options = [],
 fullWidth = false,
 required = false,
 placeholder,
 error,
 disabled = false,
 min,
 max,
 step,
 render
 } = props;

 const id = `field-${name}`;
 const baseInputStyles = `w-full px-3 py-2 rounded-lg border bg-white dark:bg-zinc-950 text-zinc-900 dark:text-zinc-100 focus:outline-none focus:ring-2 disabled:opacity-50 disabled:cursor-not-allowed ${
 error
 ? 'border-red-500 focus:ring-red-500'
 : 'border-zinc-200 dark:border-zinc-800 focus:ring-blue-500'
 }`;

 if (render) {
 return (
 <div className={fullWidth ? 'md:col-span-2' : ''}>
 <div className="mb-1 flex items-center justify-between">
 <Text variant="body" as="label" htmlFor={id} className={cn("block font-medium", error ? 'text-red-500' : 'text-zinc-500 dark:text-zinc-300')}>
 {label} {required && <span className="text-red-500">*</span>}
 </Text>
 </div>
 {render(props)}
 {error && <Text variant="label" className="mt-1 text-red-500">{error}</Text>}
 </div>
 );
 }

 const handleChange = (e: React.ChangeEvent<HTMLInputElement | HTMLSelectElement | HTMLTextAreaElement>) => {
 let newValue: any = e.target.value;
 if (type === 'number') {
 newValue = newValue === '' ? '' : parseFloat(newValue);
 }
 onChange(name, newValue);
 };

 const renderInput = () => {
 switch (type) {
 case 'select':
 return (
 <select
 id={id}
 name={name}
 value={value || ''}
 onChange={handleChange}
 required={required}
 disabled={disabled}
 className={baseInputStyles}
 >
 {options.map((opt, i) => {
 const optLabel = typeof opt === 'string' ? opt : opt.label;
 const optValue = typeof opt === 'string' ? opt : opt.value;
 return (
 <option key={i} value={optValue}>
 {optLabel}
 </option>
 );
 })}
 </select>
 );
 case 'textarea':
 return (
 <textarea
 id={id}
 name={name}
 value={value || ''}
 onChange={handleChange}
 required={required}
 placeholder={placeholder}
 disabled={disabled}
 rows={3}
 className={baseInputStyles}
 />
 );
 case 'rating':
 return (
 <div className="flex gap-2 py-1" id={id} role="radiogroup" aria-labelledby={`${id}-label`}>
 {[1, 2, 3, 4, 5].map((star) => (
 <button
 key={star}
 type="button"
 role="radio"
 aria-checked={value === star}
 disabled={disabled}
 onClick={() => onChange(name, star)}
 className={`text-2xl transition-colors disabled:opacity-50 disabled:cursor-not-allowed ${ value && value >= star ? 'text-amber-400' : 'text-zinc-300 dark:text-zinc-700 hover:text-amber-200' }`}
 >
 ★
 </button>
 ))}
 </div>
 );
 case 'number':
 case 'date':
 case 'text':
 default:
 return (
 <input
 id={id}
 type={type}
 name={name}
 value={value !== undefined && value !== null ? value : ''}
 onChange={handleChange}
 required={required}
 placeholder={placeholder}
 disabled={disabled}
 min={min}
 max={max}
 step={step}
 className={baseInputStyles}
 />
 );
 }
 };

 return (
 <div className={fullWidth ? 'md:col-span-2' : ''}>
 <Text variant="body" as="label" id={`${id}-label`} htmlFor={id} className={cn("block font-medium mb-1", error ? 'text-red-500' : 'text-zinc-500 dark:text-zinc-300')}>
 {label} {required && <span className="text-red-500" aria-hidden="true">*</span>}
 </Text>
 {renderInput()}
 {error && <Text variant="label" className="mt-1 text-red-500" role="alert">{error}</Text>}
 </div>
 );
};

export const FormField = memo(FormFieldComponent, (prev, next) => {
 return (
 prev.value === next.value &&
 prev.error === next.error &&
 prev.disabled === next.disabled &&
 prev.options === next.options
 );
});

import React from "react";
import { dashboardTokens } from "@/lib/design-system";
import { Text, SectionTitle } from "./Text";


export type DashboardInsight = {
 id: string;
 title: string;
 summary: string;
 nextStep: string;
};

type InsightPanelProps = {
 insights: DashboardInsight[];
};

export function InsightPanel({ insights }: InsightPanelProps) {
 if (insights.length === 0) {
 return (
 <div className="rounded-xl border border-border bg-card p-5">
 <SectionTitle>Insight</SectionTitle>
 <Text variant="bodySmall" muted className="mt-2">
 No patterns need attention. Keep the day simple.
 </Text>

 </div>
 );
 }

 return (
 <div className="rounded-xl border border-border bg-card p-5">
 <div className="mb-4">
 <SectionTitle>Insight</SectionTitle>
 <Text variant="bodySmall" muted>Clear next steps from today&apos;s signals.</Text>

 </div>
 <div className="flex flex-col divide-y divide-zinc-200 dark:divide-zinc-800">
 {insights.map((insight) => (
 <div key={insight.id} className="py-4 first:pt-0 last:pb-0">
 <h3 className="text-sm font-semibold text-zinc-950">{insight.title}</h3>
 <Text variant="bodySmall" muted className="mt-1">{insight.summary}</Text>

