import React, { useState, useEffect } from 'react';
import { WardrobeItem, WardrobeCategory, WARDROBE_CATEGORIES, CATEGORY_TYPES, WARDROBE_COLOURS, WARDROBE_SEASONS, WARDROBE_OCCASIONS, WARDROBE_FITS, WARDROBE_FREQUENCIES, WARDROBE_STATUSES, WARDROBE_CONDITIONS, WARDROBE_VERSATILITIES, WARDROBE_PURCHASE_REASONS, WARDROBE_OUTFIT_ROLES, WARDROBE_CLASSIFICATIONS, WARDROBE_REPLACEMENT_UNITS } from '@/types/wardrobe';
import { Modal } from '@/components/ui/Modal';
import { DynamicForm, FormSchemaSection } from '@/components/ui/DynamicForm';

interface WardrobeFormModalProps {
  isOpen: boolean;
  onClose: () => void;
  onSave: (item: Omit<WardrobeItem, 'id' | 'createdAt'>) => void;
  initialData?: WardrobeItem | null;
}

export function WardrobeFormModal({ isOpen, onClose, onSave, initialData }: WardrobeFormModalProps) {
  const [formData, setFormData] = useState<Partial<WardrobeItem>>({
    itemName: '',
    category: 'Tops',
    type: 'T-Shirt (Solid)',
    colour: 'Black',
    season: 'All Season',
    occasion: 'Casual',
    fit: 'Regular',
    frequency: 'Medium (monthly)',
    status: 'Active',
    condition: 'Good',
    versatility: 'Medium',
    cost: 0,
    purchaseReason: 'New Need',
    purchaseDate: new Date().toISOString().split('T')[0],
    lastReplacedDate: '',
    purchaseClassification: 'Testing',
    outfitRole: 'Support (used sometimes)',
    replacementValue: 1,
    replacementUnit: 'Years',
    rating: 3,
  });

  useEffect(() => {
    if (isOpen) {
      if (initialData) {
        setFormData({ ...initialData });
      } else {
        setFormData({
          itemName: '',
          category: 'Tops',
          type: 'T-Shirt (Solid)',
          colour: 'Black',
          season: 'All Season',
          occasion: 'Casual',
          fit: 'Regular',
          frequency: 'Medium (monthly)',
          status: 'Active',
          condition: 'Good',
          versatility: 'Medium',
          cost: 0,
          purchaseReason: 'New Need',
          purchaseDate: new Date().toISOString().split('T')[0],
          lastReplacedDate: '',
          purchaseClassification: 'Testing',
          outfitRole: 'Support (used sometimes)',
          replacementValue: 1,
          replacementUnit: 'Years',
          rating: 3,
        });
      }
    }
  }, [isOpen, initialData]);

  const handleChange = (name: string, value: any) => {
    setFormData(prev => {
      const updated = { ...prev, [name]: value };
      
      // Auto-update type when category changes to the first item in the new category
      if (name === 'category') {
        const cat = value as WardrobeCategory;
        const types = CATEGORY_TYPES[cat] || [];
        updated.type = types[0] || '';
      }
      
      return updated;
    });
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    onSave(formData as Omit<WardrobeItem, 'id' | 'createdAt'>);
    onClose();
  };

  const currentCategory = (formData.category as WardrobeCategory) || 'Tops';
  const availableTypes = CATEGORY_TYPES[currentCategory] || [];

  const sections: FormSchemaSection[] = [
    {
      id: 'basicInfo',
      title: 'Basic info',
      fields: [
        { name: 'itemName', label: 'Item Name', type: 'text', fullWidth: true, required: true, placeholder: "e.g., Black Levi's 501" },
        { name: 'category', label: 'Category', type: 'select', options: WARDROBE_CATEGORIES },
        { name: 'type', label: 'Type', type: 'select', options: availableTypes },
      ]
    },
    {
      id: 'appearance',
      title: 'Appearance & fit',
      fields: [
        { name: 'colour', label: 'Colour', type: 'select', options: WARDROBE_COLOURS },
        { name: 'fit', label: 'Fit', type: 'select', options: WARDROBE_FITS },
        { name: 'condition', label: 'Condition', type: 'select', options: WARDROBE_CONDITIONS },
        { name: 'season', label: 'Season', type: 'select', options: WARDROBE_SEASONS },
      ]
    },
    {
      id: 'usage',
      title: 'Usage',
      fields: [
        { name: 'occasion', label: 'Occasion', type: 'select', options: WARDROBE_OCCASIONS },
        { name: 'status', label: 'Status', type: 'select', options: WARDROBE_STATUSES },
        { name: 'frequency', label: 'Frequency', type: 'select', options: WARDROBE_FREQUENCIES },
        { name: 'versatility', label: 'Versatility', type: 'select', options: WARDROBE_VERSATILITIES },
        { name: 'outfitRole', label: 'Outfit Role', type: 'select', fullWidth: true, options: WARDROBE_OUTFIT_ROLES },
      ]
    },
    {
      id: 'purchase',
      title: 'Purchase info',
      isAdvanced: true,
      initiallyExpanded: true,
      fields: [
        { name: 'cost', label: 'Cost ($)', type: 'number', min: 0, step: 0.01 },
        { name: 'purchaseDate', label: 'Purchase Date', type: 'date' },
        { name: 'lastReplacedDate', label: 'Date Replaced/Expired', type: 'date' },
        { name: 'purchaseClassification', label: 'Classification', type: 'select', fullWidth: true, options: WARDROBE_CLASSIFICATIONS as unknown as string[] },
        { name: 'purchaseReason', label: 'Purchase Reason', type: 'select', fullWidth: true, options: WARDROBE_PURCHASE_REASONS as unknown as string[] },
        { name: 'replacementValue', label: 'Cycle Value', type: 'number', min: 1, max: 31 },
        { name: 'replacementUnit', label: 'Cycle Unit', type: 'select', options: WARDROBE_REPLACEMENT_UNITS as unknown as string[] },
      ]
    },
    {
      id: 'feedback',
      title: 'Feedback',
      fields: [
        { name: 'rating', label: 'Buy Again Rating', type: 'rating', fullWidth: true }
      ]
    }
  ];

  return (
    <Modal
      isOpen={isOpen}
      onClose={onClose}
      title={initialData ? 'Edit wardrobe item' : 'Add new item'}
      onSubmit={handleSubmit}
      submitText={initialData ? 'Save Changes' : 'Add Item'}
      accentColor="zinc"
    >
      <DynamicForm
        sections={sections}
        formData={formData}
        accentColor="zinc"
        onChange={handleChange}
      />
    </Modal>
  );
}

'use client';

import React, { useEffect } from 'react';
import { useEditor, EditorContent } from '@tiptap/react';
import StarterKit from '@tiptap/starter-kit';
import Placeholder from '@tiptap/extension-placeholder';
import CharacterCount from '@tiptap/extension-character-count';
import Underline from '@tiptap/extension-underline';
import { 
 Bold, 
 Italic, 
 Underline as UnderlineIcon, 
 List, 
 ListOrdered, 
 Heading1, 
 Heading2, 
 Undo, 
 Redo 
} from 'lucide-react';

interface EditorProps {
 content: string;
 onChange: (html: string) => void;
 placeholder?: string;
}

export function Editor({ content, onChange, placeholder }: EditorProps) {
 const editor = useEditor({
 extensions: [
 StarterKit,
 Placeholder.configure({
 placeholder: placeholder || 'Start writing your journal...',
 }),
 CharacterCount,
 Underline,
 ],
 content,
 immediatelyRender: false,
 onUpdate: ({ editor }) => {
 onChange(editor.getHTML());
 },
 });

 // Handle external content updates (like Clear button)
 useEffect(() => {
 if (editor && content !== editor.getHTML()) {
 editor.commands.setContent(content);
 }
 }, [content, editor]);

 if (!editor) {
 return null;
 }

 return (
 <div className="w-full border border-zinc-200 dark:border-zinc-800 rounded-xl overflow-hidden focus-within:ring-2 focus-within:ring-teal-500/20 transition-all duration-200">
 {/* Toolbar */}
 <div className="flex flex-wrap items-center gap-1 p-2 bg-zinc-50/50 dark:bg-zinc-900/50 border-b border-zinc-200 dark:border-zinc-800">
 <button
 onClick={() => editor.chain().focus().toggleBold().run()}
 className={`p-2 rounded-md hover:bg-zinc-200 dark:hover:bg-zinc-800 transition-colors ${editor.isActive('bold') ? 'bg-zinc-200 dark:bg-zinc-800 text-teal-600' : 'text-zinc-600 dark:text-zinc-400'}`}
 title="Bold"
 >
 <Bold className="w-4 h-4" />
 </button>
 <button
 onClick={() => editor.chain().focus().toggleItalic().run()}
 className={`p-2 rounded-md hover:bg-zinc-200 dark:hover:bg-zinc-800 transition-colors ${editor.isActive('italic') ? 'bg-zinc-200 dark:bg-zinc-800 text-teal-600' : 'text-zinc-600 dark:text-zinc-400'}`}
 title="Italic"
 >
 <Italic className="w-4 h-4" />
 </button>
 <button
 onClick={() => editor.chain().focus().toggleUnderline().run()}
 className={`p-2 rounded-md hover:bg-zinc-200 dark:hover:bg-zinc-800 transition-colors ${editor.isActive('underline') ? 'bg-zinc-200 dark:bg-zinc-800 text-teal-600' : 'text-zinc-600 dark:text-zinc-400'}`}
 title="Underline"
 >
 <UnderlineIcon className="w-4 h-4" />
 </button>
 
 <div className="w-px h-4 bg-zinc-200 dark:bg-zinc-800 mx-1" />

 <button
 onClick={() => editor.chain().focus().toggleHeading({ level: 1 }).run()}
 className={`p-2 rounded-md hover:bg-zinc-200 dark:hover:bg-zinc-800 transition-colors ${editor.isActive('heading', { level: 1 }) ? 'bg-zinc-200 dark:bg-zinc-800 text-teal-600' : 'text-zinc-600 dark:text-zinc-400'}`}
 title="Heading 1"
 >
 <Heading1 className="w-4 h-4" />
 </button>
 <button
 onClick={() => editor.chain().focus().toggleHeading({ level: 2 }).run()}
 className={`p-2 rounded-md hover:bg-zinc-200 dark:hover:bg-zinc-800 transition-colors ${editor.isActive('heading', { level: 2 }) ? 'bg-zinc-200 dark:bg-zinc-800 text-teal-600' : 'text-zinc-600 dark:text-zinc-400'}`}
 title="Heading 2"
 >
 <Heading2 className="w-4 h-4" />
 </button>

 <div className="w-px h-4 bg-zinc-200 dark:bg-zinc-800 mx-1" />

 <button
 onClick={() => editor.chain().focus().toggleBulletList().run()}
 className={`p-2 rounded-md hover:bg-zinc-200 dark:hover:bg-zinc-800 transition-colors ${editor.isActive('bulletList') ? 'bg-zinc-200 dark:bg-zinc-800 text-teal-600' : 'text-zinc-600 dark:text-zinc-400'}`}
 title="Bullet List"
 >
 <List className="w-4 h-4" />
 </button>
 <button
 onClick={() => editor.chain().focus().toggleOrderedList().run()}
 className={`p-2 rounded-md hover:bg-zinc-200 dark:hover:bg-zinc-800 transition-colors ${editor.isActive('orderedList') ? 'bg-zinc-200 dark:bg-zinc-800 text-teal-600' : 'text-zinc-600 dark:text-zinc-400'}`}
 title="Ordered List"
 >
 <ListOrdered className="w-4 h-4" />
 </button>

 <div className="flex-grow" />

 <button
 onClick={() => editor.chain().focus().undo().run()}
 className="p-2 rounded-md hover:bg-zinc-200 dark:hover:bg-zinc-800 transition-colors text-zinc-600 dark:text-zinc-400"
 title="Undo"
 disabled={!editor.can().undo()}
 >
 <Undo className="w-4 h-4" />
 </button>
 <button
 onClick={() => editor.chain().focus().redo().run()}
 className="p-2 rounded-md hover:bg-zinc-200 dark:hover:bg-zinc-800 transition-colors text-zinc-600 dark:text-zinc-400"
 title="Redo"
 disabled={!editor.can().redo()}
 >
 <Redo className="w-4 h-4" />
 </button>
 </div>

 {/* Editor Content Area */}
 <div className="prose prose-zinc dark:prose-invert max-w-none p-4 min-h-[300px]">
 <EditorContent editor={editor} className="outline-none" />
 </div>

 {/* Footer Info */}
 <div className="px-4 py-2 bg-zinc-50/30 dark:bg-zinc-900/10 border-t border-zinc-200 dark:border-zinc-800 flex justify-end items-center">
 <span className="text-xs uppercase text-zinc-400 dark:text-zinc-500 font-medium">
 {editor.storage.characterCount.characters()} characters
 </span>
 </div>
 </div>
 );
}

"use client";

import React, { useState, useMemo, useRef, useEffect } from 'react';
import { type Project, getProjectPriorityInfo, sortProjects } from './ProjectModal';



interface GanttViewProps {
 projects: Project[];
 buckets: string[];
 onSelectProject: (p: Project) => void;
}

const MONTHS = [
 'January', 'February', 'March', 'April', 'May', 'June',
 'July', 'August', 'September', 'October', 'November', 'December'
];

export function GanttView({ projects, buckets, onSelectProject }: GanttViewProps) {
 const [viewDate, setViewDate] = useState(() => {
 const d = new Date();
 d.setDate(1);
 d.setHours(0, 0, 0, 0);
 return d;
 });
 const scrollContainerRef = useRef<HTMLDivElement>(null);

 const currentYear = viewDate.getFullYear();
 const currentMonthIdx = viewDate.getMonth();

 // 1. Define Timeline Range (Exactly one month)
 const timelineRange = useMemo(() => {
 const start = new Date(viewDate);
 const end = new Date(viewDate);
 end.setMonth(start.getMonth() + 1);
 end.setDate(0); // Last day of the current month

 const days: Date[] = [];
 let current = new Date(start);
 while (current <= end) {
 days.push(new Date(current));
 current.setDate(current.getDate() + 1);
 }
 return { start, end, days };
 }, [viewDate]);

 // Number of days in the current month
 const numDays = timelineRange.days.length;

 // 2. Navigation Handlers
 const handlePrevMonth = () => {
 const next = new Date(viewDate);
 next.setMonth(viewDate.getMonth() - 1);
 setViewDate(next);
 };

 const handleNextMonth = () => {
 const next = new Date(viewDate);
 next.setMonth(viewDate.getMonth() + 1);
 setViewDate(next);
 };

 const handleMonthChange = (idx: number) => {
 const next = new Date(viewDate);
 next.setMonth(idx);
 setViewDate(next);
 };

 const handleYearChange = (year: number) => {
 const next = new Date(viewDate);
 next.setFullYear(year);
 setViewDate(next);
 };

 const handleGoToToday = () => {
 const d = new Date();
 d.setDate(1);
 d.setHours(0, 0, 0, 0);
 setViewDate(d);
 };

 // 3. Helper to get Grid Column indices for a project relative to the visible month
 // Grid columns for timeline start after the sidebar (col 1), so timeline days are col 2 to numDays + 1
 const getProjectCols = (project: Project) => {
 const due = new Date(project.dueDate + 'T12:00:00');
 let start: Date;
 
 if (project.startDate) {
 start = new Date(project.startDate + 'T12:00:00');
 } else {
 // Fallback: 2 weeks before due date
 start = new Date(due);
 start.setDate(due.getDate() - 14);
 }

 // Clipping: If start is before month start, treat as month start
 const barStart = start < timelineRange.start ? timelineRange.start : start;
 // Clipping: If due is after month end, treat as month end
 const barEnd = due > timelineRange.end ? timelineRange.end : due;

 // Check if project is even visible in this month
 if (due < timelineRange.start || start > timelineRange.end) {
 return null;
 }

 // Grid columns are 1-indexed. Col 1 is sidebar.
 // Timeline Day 1 is Col 2.
 const startIdx = Math.floor((barStart.getTime() - timelineRange.start.getTime()) / (1000 * 60 * 60 * 24)) + 2;
 const endIdx = Math.floor((barEnd.getTime() - timelineRange.start.getTime()) / (1000 * 60 * 60 * 24)) + 3;

 return { 
 startIdx, 
 endIdx, 
 isClippedStart: start < timelineRange.start, 
 isClippedEnd: due > timelineRange.end 
 };
 };

 const leftColumnWidth = 240; // Increased sidebar for more readable titles

 // Years for dropdown (Current Year ± 2)
 const years = useMemo(() => {
 const y = new Date().getFullYear();
 return [y - 2, y - 1, y, y + 1, y + 2];
 }, []);

 const isTodayVisible = useMemo(() => {
 const now = new Date();
 return now >= timelineRange.start && now <= timelineRange.end;
 }, [timelineRange]);

 const gridTemplateColumns = `${leftColumnWidth}px repeat(${numDays}, 1fr)`;

 return (
 <div className="bg-white dark:bg-zinc-950 border border-zinc-200 dark:border-zinc-800 rounded-3xl overflow-hidden flex flex-col shadow-xl h-[700px]">
 
 {/* Header Controls */}
 <div className="px-6 py-4 border-b border-zinc-100 dark:border-zinc-800 flex items-center justify-between bg-zinc-50/50 dark:bg-zinc-900/20">
 <div className="flex items-center gap-6">
 <div className="flex items-center gap-2">
 <button 
 onClick={handlePrevMonth}
 className="p-2 rounded-full hover:bg-zinc-100 dark:hover:bg-zinc-800 text-zinc-500 transition-colors"
 >
 <svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round"><path d="m15 18-6-6 6-6"/></svg>
 </button>
 
 <div className="flex items-center gap-1">
 <select 
 value={currentMonthIdx}
 onChange={(e) => handleMonthChange(parseInt(e.target.value))}
 className="bg-transparent text-lg font-semibold text-zinc-900 dark:text-white focus:outline-none cursor-pointer hover:bg-zinc-100 dark:hover:bg-zinc-800 px-2 py-1 rounded-lg"
 >
 {MONTHS.map((m, i) => (
 <option key={m} value={i} className="bg-white dark:bg-zinc-900 text-sm font-medium">{m}</option>
 ))}
 </select>
 <select 
 value={currentYear}
 onChange={(e) => handleYearChange(parseInt(e.target.value))}
 className="bg-transparent text-lg font-semibold text-zinc-900 dark:text-white focus:outline-none cursor-pointer hover:bg-zinc-100 dark:hover:bg-zinc-800 px-2 py-1 rounded-lg"
 >
 {years.map(y => (
 <option key={y} value={y} className="bg-white dark:bg-zinc-900 text-sm font-medium">{y}</option>
 ))}
 </select>
 </div>

 <button 
 onClick={handleNextMonth}
 className="p-2 rounded-full hover:bg-zinc-100 dark:hover:bg-zinc-800 text-zinc-500 transition-colors"
 >
 <svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round"><path d="m9 18 6-6-6-6"/></svg>
 </button>
 </div>
 </div>

 <div className="flex items-center gap-3">
 <button 
 onClick={handleGoToToday}
 className={`px-4 py-2 text-xs font-semibold rounded-lg transition-all ${isTodayVisible && new Date().getMonth() === currentMonthIdx && new Date().getFullYear() === currentYear ? 'bg-zinc-100 dark:bg-zinc-800 text-zinc-400 cursor-default' : 'bg-zinc-900 dark:bg-zinc-100 text-white dark:text-black hover:opacity-90 shadow-sm'}`}

 >
 Go to Today
 </button>
 </div>
 </div>

 {/* Main Gantt Body */}
 <div 
 ref={scrollContainerRef}
 className="flex-1 overflow-y-auto overflow-x-hidden relative custom-scrollbar select-none"
 >
 <div className="w-full relative min-h-full">
 
 {/* Timeline Header Row (CSS Grid) */}
 <div 
 className="sticky top-0 z-20 grid bg-white dark:bg-zinc-950 border-b border-zinc-100 dark:border-zinc-800"
 style={{ gridTemplateColumns }}
 >
 <div className="sticky left-0 z-30 bg-white dark:bg-zinc-950 border-r border-zinc-200/50 dark:border-zinc-800/50 px-6 py-4 font-extrabold text-sm uppercase text-zinc-500">
 Active Projects
 </div>
 {timelineRange.days.map((day, i) => {
 const now = new Date();
 const isToday = day.getDate() === now.getDate() && day.getMonth() === now.getMonth() && day.getFullYear() === now.getFullYear();
 const isWeekend = day.getDay() === 0 || day.getDay() === 6;

 return (
 <div 
 key={i} 
 className={`border-r border-zinc-100/50 dark:border-zinc-800/30 flex flex-col items-center justify-center py-2 h-14 ${isToday ? 'bg-teal-500/5' : isWeekend ? 'bg-zinc-50/50 dark:bg-zinc-900/10' : ''}`}
 >
 <span className="text-xs font-semibold text-zinc-400 uppercase">
 {day.toLocaleDateString(undefined, { weekday: 'narrow' })}
 </span>
 <span className={`text-sm font-semibold ${isToday ? 'text-teal-500' : 'text-zinc-600 dark:text-zinc-300'}`}>
 {day.getDate()}
 </span>
 </div>
 );
 })}
 </div>

 {/* Grid Lines Overlay Container */}
 <div className="absolute inset-x-0 top-14 bottom-0 pointer-events-none">
 <div className="grid h-full w-full" style={{ gridTemplateColumns }}>
 <div className="border-r border-zinc-200/50 dark:border-zinc-800/50"></div> {/* Sidebar column */}
 {timelineRange.days.map((day, i) => {
 const isWeekend = day.getDay() === 0 || day.getDay() === 6;
 return (
 <div key={i} className={`h-full border-r border-zinc-200/40 dark:border-zinc-800/40 ${isWeekend ? 'bg-zinc-100/30 dark:bg-zinc-900/40' : ''}`}></div>
 );
 })}
 </div>
 </div>

 {/* Today Line (CSS Grid based) */}
 {isTodayVisible && (
 <div 
 className="absolute inset-x-0 top-0 bottom-0 z-10 pointer-events-none grid h-full w-full" 
 style={{ gridTemplateColumns }}
 >
 <div style={{ gridColumn: new Date().getDate() + 1 }} className="flex justify-center h-full">
 <div className="w-px bg-teal-500/50 h-full relative">
 <div className="sticky top-14 -ml-[5.5px] w-3 h-3 rounded-full bg-teal-500 shadow-lg shadow-teal-500/50 border-2 border-white dark:border-zinc-950"></div>
 </div>
 </div>
 </div>
 )}

 {/* Rows Container */}
 <div className="relative z-0">
 {sortProjects(projects).map(project => {
 const priority = getProjectPriorityInfo(project);
 const cols = getProjectCols(project);
 
 return (
 <div 
 key={project.id} 
 className="group grid items-center hover:bg-zinc-50/50 dark:hover:bg-zinc-900/20 transition-colors border-b border-zinc-50 dark:border-zinc-900"
 style={{ gridTemplateColumns }}
 >
 {/* Sidebar Project Info */}
 <div 
 onClick={() => onSelectProject(project)}
 className="sticky left-0 z-20 bg-white dark:bg-zinc-950 group-hover:bg-zinc-50 dark:group-hover:bg-zinc-900 border-r border-zinc-200/50 dark:border-zinc-800/50 px-6 py-5 cursor-pointer flex flex-col justify-center gap-1.5"
 >
 <h4 className="text-base font-semibold text-zinc-900 dark:text-white truncate group-hover:text-teal-600 dark:group-hover:text-teal-400 transition-colors">
 {project.title}
 </h4>
 <span className="text-[11px] font-semibold uppercase opacity-70 flex items-center gap-1.5">
 <span>{priority.label}</span>
 </span>
 </div>

 {/* Responsive Bar Column Placement */}
 {cols && (
 <div 
 className="relative h-16 flex items-center"
 style={{ 
 gridColumn: `${cols.startIdx} / ${cols.endIdx}`
 }}
 >
 <div 
 onClick={() => onSelectProject(project)}
 className={`w-full h-8 rounded-lg flex items-center px-3 cursor-pointer transition-all hover:scale-[1.01] hover:shadow-lg hover:z-50 group/bar border ${priority.classes} shadow-sm overflow-hidden`}
 >
 {/* Clipped Indicators */}
 {cols.isClippedStart && (
 <div className="absolute left-0 top-0 bottom-0 w-1.5 bg-zinc-900/10 dark:bg-white/10 flex items-center justify-center">
 <span className="text-[8px] opacity-40">«</span>
 </div>
 )}
 {cols.isClippedEnd && (
 <div className="absolute right-0 top-0 bottom-0 w-1.5 bg-zinc-900/10 dark:bg-white/10 flex items-center justify-center">
 <span className="text-[8px] opacity-40">»</span>
 </div>
 )}

 <span className={`text-sm font-semibold whitespace-nowrap overflow-hidden text-ellipsis px-1 ${cols.isClippedStart ? 'ml-1.5' : ''} ${cols.isClippedEnd ? 'mr-1.5' : ''}`}>
 {project.title}
 </span>
 
 {/* Hover Tooltip */}
 <div className="invisible group-hover/bar:visible absolute -top-12 left-1/2 -translate-x-1/2 bg-zinc-950 dark:bg-white text-white dark:text-black text-xs font-semibold py-2 px-3 rounded-lg whitespace-nowrap z-50 shadow-2xl border border-white/10 dark:border-black/5 animate-in fade-in zoom-in-95 duration-150">
 {project.startDate || '—'} → {project.dueDate}
 </div>
 </div>
 </div>
 )}
 </div>
 );
 })}
 </div>

 <div className="h-20"></div>
 </div>
 </div>
 </div>
 );
}

