"use client";

import { useEffect, useCallback, useRef, useState } from 'react';
import { supabase } from '@/lib/supabase';
import { getPrefixedKey } from '@/lib/keys';
import { ALL_SYNC_KEYS, LEGACY_KEY_MIGRATION } from '@/lib/sync-keys';

export function useSync() {
 const [isReady, setIsReady] = useState(false);
 const [session, setSession] = useState<any>(null);
 const [syncStatus, setSyncStatus] = useState<'idle' | 'syncing' | 'error' | 'unauthenticated' | 'connected' | 'initializing' | 'local'>('initializing');
 const isSyncingFromRemote = useRef(false);
 const isDevelopment = process.env.NODE_ENV === 'development' || (typeof window !== 'undefined' && (window.location.hostname === 'localhost' || window.location.hostname === '127.0.0.1'));

 // Diagnostic Log (Runs once)
 useEffect(() => {
 const projectID = process.env.NEXT_PUBLIC_DASHBOARD_ID;
 console.log(`[Sync] Dashboard ID: ${projectID || 'NONE (unprefixed)'}`);
 }, []);

 // --- 0. Session Management ---
 useEffect(() => {
 supabase.auth.getSession().then(({ data: { session } }) => {
 setSession(session);
 if (!session) {
 console.warn('[Sync] No session found. Cloud sync will be disabled.');
 setSyncStatus('unauthenticated');
 } else {
 console.log('[Sync] Session established for:', session.user?.email);
 }
 });

 const { data: { subscription } } = supabase.auth.onAuthStateChange((_event, session) => {
 setSession(session);
 if (session) {
 console.log('[Sync] Auth change: Authenticated');
 setSyncStatus('idle');
 } else {
 console.warn('[Sync] Auth change: Unauthenticated');
 setSyncStatus('unauthenticated');
 }
 });

 return () => subscription.unsubscribe();
 }, []);

 // --- 1. Push Local Changes to Supabase ---
 const pushToSupabase = useCallback(async (key: string, value: string | null) => {
 if (isSyncingFromRemote.current) return;
 if (!value) return;
 if (!session) {
 // Don't log error here as it might be normal on localhost
 return;
 }

 if (isDevelopment) {
 console.log(`[Sync] Development: Skipping push for ${key} to protect cloud data.`);
 setSyncStatus('local');
 setTimeout(() => setSyncStatus('idle'), 2000);
 return;
 }

 const prefixedKey = getPrefixedKey(key);

 const performPush = async (attempt = 0): Promise<boolean> => {
 try {
 const parsedValue = JSON.parse(value);
 setSyncStatus('syncing');
 
 const { error } = await supabase
 .from('dashboard_data')
 .upsert({ 
 key: prefixedKey, 
 value: parsedValue, 
 updated_at: new Date().toISOString() 
 }, { onConflict: 'key' });

 if (error) {
 // If it's a network/transient error and we have retries left
 if (attempt < 2 && !['401', '403', '409', '42P01'].includes(error.code)) {
 const delay = Math.pow(2, attempt) * 1000;
 console.warn(`[Sync] Push failed for ${prefixedKey}, retrying in ${delay}ms...`, error.message);
 await new Promise(r => setTimeout(r, delay));
 return performPush(attempt + 1);
 }
 
 // Final failure or non-retryable error
 if (error.code === '401' || error.code === '403') {
 setSyncStatus('unauthenticated');
 } else {
 console.error(`[Sync] Error pushing ${prefixedKey} (Code: ${error.code}):`, error.message || error);
 setSyncStatus('error');
 }
 return false;
 }

 setSyncStatus('connected'); // Show we are talking to the cloud
 setTimeout(() => setSyncStatus('idle'), 2000); // Back to idle after showing success
 console.log(`[Sync] Cloud update: ${prefixedKey} pushed.`);
 return true;
 } catch (e: any) {
 console.error(`[Sync] Failed to parse ${prefixedKey} for push:`, e.message || e);
 setSyncStatus('error');
 return false;
 }
 };

 await performPush();
 }, [session]);

 // --- 2. Pull Initial Data from Supabase & Initial Push ---
 useEffect(() => {
 const initSync = async () => {
 console.log('[Sync] Initializing pull from cloud...');
 setSyncStatus('initializing');

 // 0. Legacy Key Migration (Local)
 for (const [legacyKey, newKey] of Object.entries(LEGACY_KEY_MIGRATION)) {
 const legacyPrefixed = getPrefixedKey(legacyKey);
 const newPrefixed = getPrefixedKey(newKey);
 const legacyVal = localStorage.getItem(legacyPrefixed);
 
 if (legacyVal && !localStorage.getItem(newPrefixed)) {
 console.log(`[Sync] Migrating legacy local data: ${legacyKey} -> ${newKey}`);
 localStorage.setItem(newPrefixed, legacyVal);
 }
 }
 
 // 1. Pull from Supabase (Skipped in development)
 let projectRemoteData: any[] = [];
 if (session && !isDevelopment) {
 const { data: remoteData, error } = await supabase.from('dashboard_data').select('*');

 if (error) {
 console.error('[Sync] Error loading initial cloud data:', error.message || error);
 setSyncStatus('error');
 setIsReady(true);
 return;
 }

 // Filter for keys that belong to this project
 const projectID = process.env.NEXT_PUBLIC_DASHBOARD_ID;
 projectRemoteData = remoteData?.filter(r => 
 projectID ? r.key.startsWith(`${projectID}:`) : !r.key.includes(':')
 ) || [];
 } else if (isDevelopment) {
 console.log('[Sync] Development mode: Skipping initial cloud pull.');
 }

 const remoteKeysMap = new Map(projectRemoteData.map(r => [r.key, r.value]));

 // a) Load remote data into local storage
 if (projectRemoteData.length > 0) {
 isSyncingFromRemote.current = true;
 projectRemoteData.forEach((row) => {
 const parts = row.key.split(':');
 const baseKey = parts[parts.length - 1];
 if (baseKey && ALL_SYNC_KEYS.includes(baseKey)) {
 const currentLocal = localStorage.getItem(row.key);
 const remoteVal = JSON.stringify(row.value);
 
 // Only update if different
 if (currentLocal !== remoteVal) {
 console.log(`[Sync] Updating local '${baseKey}' from cloud.`);
 localStorage.setItem(row.key, remoteVal);
 window.dispatchEvent(new CustomEvent('local-storage-change', { detail: { key: baseKey } }));
 }
 }
 });
 isSyncingFromRemote.current = false;
 console.log(`[Sync] Synchronized ${projectRemoteData.length} records from Supabase.`);
 }

 // c) Push local data that isn't on remote yet (Migration) (Skipped in development)
 if (session && !isDevelopment) {
 for (const baseKey of ALL_SYNC_KEYS) {
 const prefixedKey = getPrefixedKey(baseKey);
 if (!remoteKeysMap.has(prefixedKey)) {
 const localVal = localStorage.getItem(prefixedKey);
 if (localVal) {
 console.log(`[Sync] Initial push of '${baseKey}' to cloud.`);
 await pushToSupabase(baseKey, localVal);
 }
 }
 }
 } else if (session && isDevelopment) {
 console.log('[Sync] Development mode: Initial push/migrations skipped.');
 }

 setIsReady(true);
 if (session) setSyncStatus('connected');
 setTimeout(() => setSyncStatus('idle'), 1000);
 console.log('[Sync] Ready.');
 };

 if (session !== undefined) {
 initSync();
 }
 }, [pushToSupabase, session]);

 // --- 3. Listen for Local Storage Changes ---
 useEffect(() => {
 // Other tabs
 const handleStorageChange = (e: StorageEvent) => {
 if (e.key && !isSyncingFromRemote.current) {
 // Find if this prefixed key matches one of our sync keys
 const baseKey = ALL_SYNC_KEYS.find(k => getPrefixedKey(k) === e.key);
 if (baseKey) {
 pushToSupabase(baseKey, e.newValue);
 }
 }
 };

 // Current tab (via setSyncedItem)
 const handleLocalUpdate = (e: any) => {
 if (e.detail && ALL_SYNC_KEYS.includes(e.detail.key) && !isSyncingFromRemote.current) {
 const val = localStorage.getItem(getPrefixedKey(e.detail.key));
 pushToSupabase(e.detail.key, val);
 }
 };

 window.addEventListener('storage', handleStorageChange);
 window.addEventListener('local-storage-change', handleLocalUpdate);

 return () => {
 window.removeEventListener('storage', handleStorageChange);
 window.removeEventListener('local-storage-change', handleLocalUpdate);
 };
 }, [pushToSupabase]);

 // --- 4. Listen for Remote Changes (Realtime) ---
 useEffect(() => {
 if (!session || isDevelopment) return;

 const channel = supabase
 .channel('dashboard-changes')
 .on(
 'postgres_changes',
 { event: '*', schema: 'public', table: 'dashboard_data' },
 (payload) => {
 const newRow = payload.new as any;
 if (!newRow || !newRow.key) return;

 // Check if key belongs to this project
 const projectID = process.env.NEXT_PUBLIC_DASHBOARD_ID;
 const isProjectKey = projectID ? newRow.key.startsWith(`${projectID}:`) : !newRow.key.includes(':');
 
 if (isProjectKey) {
 const parts = newRow.key.split(':');
 const baseKey = parts[parts.length - 1];
 
 if (baseKey && ALL_SYNC_KEYS.includes(baseKey)) {
 console.log(`[Sync] Incoming cloud update: ${newRow.key}`);
 
 const currentLocal = localStorage.getItem(newRow.key);
 const remoteVal = JSON.stringify(newRow.value);
 
 if (currentLocal !== remoteVal) {
 isSyncingFromRemote.current = true;
 localStorage.setItem(newRow.key, remoteVal);
 window.dispatchEvent(new CustomEvent('local-storage-change', { detail: { key: baseKey } }));
 
 // Visual feedback of sync
 setSyncStatus('connected');
 setTimeout(() => setSyncStatus('idle'), 2000);
 
 isSyncingFromRemote.current = false;
 }
 }
 }
 }
 )
 .subscribe((status: string) => {
 console.log(`[Sync] Realtime channel status: ${status}`);
 if (status === 'SUBSCRIBED') {
 setSyncStatus('connected');
 setTimeout(() => setSyncStatus('idle'), 1000);
 }
 if (status === 'CHANNEL_ERROR' || status === 'TIMED_OUT') {
 console.error('[Sync] Realtime connection failed. Check if Realtime is enabled on the table and RLS allows access.');
 setSyncStatus('error');
 }
 });

 return () => {
 supabase.removeChannel(channel);
 };
 }, [session]);

 return { isReady, syncStatus, isDevelopment };
}

"use client";

import { useState, useEffect, useMemo } from 'react';
import { getPrefixedKey } from '@/lib/keys';
import { SYNC_KEYS } from '@/lib/sync-keys';
import { MedicineItem, SupplementItem, InventoryStatus } from '@/types/health-system';

export type PriorityTier = 'CRITICAL' | 'DAILY' | 'MAINTENANCE';

export interface PulseAction {
  id: string;
  label: string;
  href: string;
  tier: PriorityTier;
  type: string;
}

export interface SystemPulse {
  ready: boolean;
  score: number; // 0-100
  scoreLabel: string;
  actions: PulseAction[];
  milestone: {
    title: string;
    daysDesc: string;
    bucket: string;
  } | null;
  stats: {
    healthReadiness: number;
    goalHealth: number;
    habitConsistency: number;
  };
}

export function useSystemPulse() {
  const [pulse, setPulse] = useState<SystemPulse>({
    ready: false,
    score: 0,
    scoreLabel: 'Calculating...',
    actions: [],
    milestone: null,
    stats: { healthReadiness: 0, goalHealth: 0, habitConsistency: 0 }
  });

  useEffect(() => {
    const calculatePulse = () => {
      const today = new Date();
      today.setHours(0, 0, 0, 0);
      const todayStr = today.toISOString().split('T')[0];

      // --- 1. HEALTH DATA ---
      const healthKeys = [
        SYNC_KEYS.HEALTH_MEDICINE,
        SYNC_KEYS.HEALTH_TRAVEL_KIT,
        SYNC_KEYS.HEALTH_FIRST_AID_HOME,
        SYNC_KEYS.HEALTH_FIRST_AID_MOBILE,
        SYNC_KEYS.HEALTH_SUPPLEMENTS
      ];

      let totalHealthItems = 0;
      let okHealthItems = 0;
      const healthIssues: { type: InventoryStatus; name: string }[] = [];

      healthKeys.forEach(key => {
        const saved = localStorage.getItem(getPrefixedKey(key));
        if (saved) {
          try {
            const items = JSON.parse(saved);
            if (Array.isArray(items)) {
              items.forEach((item: any) => {
                totalHealthItems++;
                const name = item.itemName || item.medicineName || item.name || 'Item';
                const expiry = new Date(item.expiryDate);
                expiry.setHours(0, 0, 0, 0);

                if (expiry < today) {
                  healthIssues.push({ type: 'EXPIRED', name });
                } else if (item.quantity === 0) {
                  healthIssues.push({ type: 'MISSING', name });
                } else if (item.quantity < (item.targetQuantity || 1)) {
                  healthIssues.push({ type: 'LOW', name });
                } else {
                  okHealthItems++;
                }
              });
            }
          } catch (e) { console.error("Error parsing block:", e); }
        }
      });

      const healthReadiness = totalHealthItems > 0 ? (okHealthItems / totalHealthItems) * 100 : 100;

      // --- 2. GOALS DATA ---
      const savedProjects = localStorage.getItem(getPrefixedKey('goals_projects'));
      let totalProjects = 0;
      let onTrackProjects = 0;
      let overdueCount = 0;
      let dueTodayCount = 0;
      let nextMilestone: any = null;

      if (savedProjects) {
        try {
          const projects = JSON.parse(savedProjects);
          if (Array.isArray(projects)) {
            const activeProjects = projects.filter(p => !p.isCompleted && p.status !== 'completed');
            totalProjects = activeProjects.length;

            activeProjects.forEach(p => {
              if (p.dueDate) {
                if (p.dueDate < todayStr) overdueCount++;
                else if (p.dueDate === todayStr) dueTodayCount++;

                // Tracking milestone
                if (p.dueDate >= todayStr) {
                  if (!nextMilestone || p.dueDate < nextMilestone.dueDate) {
                    nextMilestone = p;
                  }
                }
              }

              // Simple on-track logic: not overdue
              if (!p.dueDate || p.dueDate >= todayStr) onTrackProjects++;
            });
          }
        } catch (e) { console.error("Error parsing block:", e); }
      }

      const goalHealth = totalProjects > 0 ? (onTrackProjects / totalProjects) * 100 : 100;

      // --- 3. HABITS DATA ---
      const savedHabits = localStorage.getItem(getPrefixedKey('os_habits'));
      let pendingHabitsCount = 0;
      let habitSuccessRate = 0;

      if (savedHabits) {
        try {
          const habits = JSON.parse(savedHabits);
          if (Array.isArray(habits)) {
            const mKey = `${today.getFullYear()}-${today.getMonth()}`;
            const dayIdx = today.getDate() - 1;

            habits.forEach(h => {
              const isActive = !h.monthScope || h.monthScope.includes(mKey);
              if (!isActive) return;
              const status = h.records?.[mKey]?.[dayIdx];
              if (status === 'none' || status === undefined) {
                pendingHabitsCount++;
              }
            });

            // Calculate success rate for the last 7 days
            let done = 0, total = 0;
            for (let i = 0; i < 7; i++) {
              const d = new Date(today);
              d.setDate(today.getDate() - i);
              const mk = `${d.getFullYear()}-${d.getMonth()}`;
              const di = d.getDate() - 1;
              habits.forEach(h => {
                const active = !h.monthScope || h.monthScope.includes(mk);
                if (!active) return;
                const s = h.records?.[mk]?.[di];
                if (s === 'done') { done++; total++; }
                else if (s === 'missed') { total++; }
              });
            }
            habitSuccessRate = total > 0 ? (done / total) * 100 : 100;
          }
        } catch (e) { console.error("Error parsing block:", e); }
      }

      // --- 4. AGGREGATE PULSE ---
      // Weighting: Health (40%), Goals (35%), Habits (25%)
      const pulseScore = Math.round(
        (healthReadiness * 0.4) + (goalHealth * 0.35) + (habitSuccessRate * 0.25)
      );

      const scoreLabel = pulseScore >= 90 ? 'Stable' : pulseScore >= 75 ? 'Optimal' : pulseScore >= 50 ? 'Warning' : 'Critical';

      // --- 5. PRIORITY ACTIONS ---
      const actions: PulseAction[] = [];

      // Critical Tiers
      const expired = healthIssues.filter(i => i.type === 'EXPIRED');
      if (expired.length > 0) {
        actions.push({
          id: 'health-expired',
          tier: 'CRITICAL',
          type: 'HEALTH',
          label: `Replace ${expired[0].name}${expired.length > 1 ? ` & ${expired.length - 1} more` : ''}`,
          href: '/health-system?filter=EXPIRED'
        });
      }
      if (overdueCount > 0) {
        actions.push({
          id: 'goals-overdue',
          tier: 'CRITICAL',
          type: 'GOALS',
          label: `${overdueCount} task${overdueCount !== 1 ? 's' : ''} overdue`,
          href: '/goals'
        });
      }

      // Daily Tiers
      if (dueTodayCount > 0) {
        actions.push({
          id: 'goals-today',
          tier: 'DAILY',
          type: 'GOALS',
          label: `${dueTodayCount} task${dueTodayCount !== 1 ? 's' : ''} due today`,
          href: '/goals'
        });
      }
      if (pendingHabitsCount > 0) {
        actions.push({
          id: 'habits-today',
          tier: 'DAILY',
          type: 'HABITS',
          label: `${pendingHabitsCount} habit${pendingHabitsCount !== 1 ? 's' : ''} pending`,
          href: '/habits'
        });
      }

      // Maintenance Tiers
      const missing = healthIssues.filter(i => i.type === 'MISSING');
      if (missing.length > 0) {
        actions.push({
          id: 'health-missing',
          tier: 'MAINTENANCE',
          type: 'HEALTH',
          label: `Restock ${missing[0].name}`,
          href: '/health-system?filter=MISSING'
        });
      }
      const low = healthIssues.filter(i => i.type === 'LOW');
      if (low.length > 0) {
        actions.push({
          id: 'health-low',
          tier: 'MAINTENANCE',
          type: 'HEALTH',
          label: `Refill ${low[0].name}`,
          href: '/health-system?filter=LOW'
        });
      }

      // --- 6. MILESTONE PREP ---
      let milestoneData = null;
      if (nextMilestone) {
        const msDate = new Date(nextMilestone.dueDate);
        const diff = Math.ceil((msDate.getTime() - today.getTime()) / (1000 * 60 * 60 * 24));
        milestoneData = {
          title: nextMilestone.title,
          daysDesc: diff === 0 ? 'Due Today' : diff === 1 ? 'Due Tomorrow' : `In ${diff} days`,
          bucket: nextMilestone.bucketId || 'Goal'
        };
      }

      setPulse({
        ready: true,
        score: pulseScore,
        scoreLabel,
        actions,
        milestone: milestoneData,
        stats: { healthReadiness, goalHealth, habitConsistency: habitSuccessRate }
      });
    };

    calculatePulse();

    const handleStorage = (e: any) => {
      calculatePulse();
    };
    window.addEventListener('local-storage-change', handleStorage);
    window.addEventListener('storage', calculatePulse); // Cross-tab support

    return () => {
      window.removeEventListener('local-storage-change', handleStorage);
      window.removeEventListener('storage', calculatePulse);
    };
  }, []);

  return pulse;
}

"use client";

import { useState, useEffect, useCallback } from 'react';
import { WardrobeItem } from '@/types/wardrobe';
import { SYNC_KEYS } from '@/lib/sync-keys';
import { getPrefixedKey } from '@/lib/keys';

const STORAGE_KEY = SYNC_KEYS.WARDROBE_INVENTORY;

export function useWardrobe() {
 const [items, setItems] = useState<WardrobeItem[]>([]);
 const [isLoaded, setIsLoaded] = useState(false);

 // Load from local storage
 const loadItems = useCallback(() => {
 try {
 const prefixedKey = getPrefixedKey(STORAGE_KEY);
 const stored = localStorage.getItem(prefixedKey);
 if (stored) {
 setItems(JSON.parse(stored));
 }
 } catch (e) {
 console.error('Failed to load wardrobe items', e);
 } finally {
 setIsLoaded(true);
 }
 }, []);

 useEffect(() => {
 loadItems();

 const handleStorageChange = (e: StorageEvent) => {
 const prefixedKey = getPrefixedKey(STORAGE_KEY);
 if (e.key === prefixedKey) {
 loadItems();
 }
 };

 const handleLocalUpdate = (e: any) => {
 if (e.detail && e.detail.key === STORAGE_KEY) {
 loadItems();
 }
 };

 window.addEventListener('storage', handleStorageChange);
 window.addEventListener('local-storage-change', handleLocalUpdate);

 return () => {
 window.removeEventListener('storage', handleStorageChange);
 window.removeEventListener('local-storage-change', handleLocalUpdate);
 };
 }, [loadItems]);

 const saveItems = (newItems: WardrobeItem[]) => {
 setItems(newItems);
 const prefixedKey = getPrefixedKey(STORAGE_KEY);
 localStorage.setItem(prefixedKey, JSON.stringify(newItems));
 
 // Dispatch event for sync
 window.dispatchEvent(new CustomEvent('local-storage-change', { 
 detail: { key: STORAGE_KEY } 
 }));
 };

 const addItem = (item: Omit<WardrobeItem, 'id' | 'createdAt'>) => {
 const newItem: WardrobeItem = {
 ...item,
 id: crypto.randomUUID(),
 createdAt: new Date().toISOString()
 };
 saveItems([...items, newItem]);
 };

 const updateItem = (id: string, updates: Partial<WardrobeItem>) => {
 const newItems = items.map(item => 
 item.id === id ? { ...item, ...updates } : item
 );
 saveItems(newItems);
 };

 const deleteItem = (id: string) => {
 saveItems(items.filter(item => item.id !== id));
 };

 return {
 items,
 isLoaded,
 addItem,
 updateItem,
 deleteItem
 };
}

import { getPrefixedKey } from './keys';
